export interface Cours8Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── Logique de la modulation (18) ──
  { q:"Une modulation est :", opts:["Un emprunt d'accord étranger","Un changement durable de tonalité principale — le centre tonal se déplace","Une tonicisation prolongée","Un changement de tempo"], a:1, fb:"La modulation installe durablement une nouvelle tonalité — elle est confirmée par une cadence parfaite dans le nouveau centre. Elle se distingue de l'emprunt (momentané) et de la tonicisation (bref)." },
  { q:"Quelle condition rend une modulation 'réelle' (durable) ?", opts:["Utiliser un accord diminué","La confirmation par une cadence parfaite dans la nouvelle tonalité, suivie d'un séjour","L'utilisation d'accords renversés","La présence d'une sensible artificielle"], a:1, fb:"Une modulation n'est pas une simple couleur passagère — elle installe un nouveau centre tonal. Pour cela, une cadence parfaite (V–I) dans le nouveau ton confirme l'arrivée. Sans ce séjour, c'est une tonicisation." },
  { q:"Qu'est-ce qui distingue fondamentalement une modulation d'un emprunt ?", opts:["La durée — modulation = durable, emprunt = momentané","La hauteur des notes","Le nombre de voix","L'armure uniquement"], a:0, fb:"Un emprunt est une couleur passagère — on revient immédiatement à la tonalité principale. La modulation déplace durablement le centre tonal — on reste dans la nouvelle tonalité pendant plusieurs mesures." },
  { q:"La modulation par accord pivot est la plus fréquente car :", opts:["Elle est la plus rapide","Elle est la plus fluide — l'accord pivot appartient aux deux tonalités, assurant une transition sans rupture","Elle évite la dominante","Elle ne nécessite pas de cadence"], a:1, fb:"L'accord pivot appartient simultanément à la tonalité de départ et à celle d'arrivée. On le réinterprète (même accord, nouvelle fonction) — la transition est donc imperceptible, sans rupture." },
  { q:"Pour confirmer l'arrivée dans une nouvelle tonalité, on utilise :", opts:["Un accord renversé","Une cadence parfaite (V–I) dans le nouveau ton","Un accord de sixte napolitaine","Une pédale de tonique"], a:1, fb:"La cadence parfaite dans la nouvelle tonalité — V (à l'état fondamental) → I (à l'état fondamental) — est le signal le plus fort que le centre tonal a changé. Sans elle, la modulation reste ambiguë." },
  { q:"Les tons voisins sont privilégiés pour les modulations car :", opts:["Ils ont moins de notes","Ils partagent de nombreux accords — les pivots abondent, la transition est douce","Ils sont plus graves","Ils utilisent moins d'altérations"], a:1, fb:"Tons voisins = 6-7 notes communes. Plus les deux tonalités partagent de notes et d'accords, plus il y a de pivots possibles et plus la modulation est fluide. Les tons éloignés nécessitent des transitions plus abruptes." },
  { q:"Une modulation directe (sans pivot) crée :", opts:["Une transition très douce","Une rupture brutale — effet théâtral ou dramatique","Une cadence imparfaite","Un retard harmonique"], a:1, fb:"La modulation directe (sans accord de transition) saute brusquement d'une tonalité à l'autre. Cet effet peut être voulu — pour marquer un changement dramatique — mais il reste une exception stylistique." },
  { q:"La tonique de la tonalité d'arrivée est généralement évitée comme pivot car :", opts:["Elle est toujours diminuée","Elle est trop marquée — entendre la tonique du nouveau ton avant la cadence affaiblit la surprise de l'arrivée","Elle n'appartient pas à la gamme de départ","Elle crée des octaves parallèles"], a:1, fb:"Si on entend la tonique de G (G majeur) trop tôt comme accord diatonique de C (V de C), l'oreille anticipe l'arrivée. L'accord pivot idéal est neutre — il ne préfigure pas trop nettement la destination." },
  { q:"Combien de temps faut-il rester dans la nouvelle tonalité pour valider une modulation ?", opts:["Un seul accord suffit","Au moins une cadence parfaite — plusieurs mesures de préférence","Exactement 4 mesures","Une octave de durée"], a:1, fb:"Une modulation n'est validée que si on séjourne dans la nouvelle tonalité. Un seul accord de la nouvelle tonalité, c'est une tonicisation. Il faut au minimum une cadence parfaite, idéalement plusieurs mesures." },
  { q:"Dans la progression C–F–G7–C–Am–D7–G, la modulation de C vers G est confirmée par :", opts:["Am","D7","G — l'accord final","La présence de F# dans D7"], a:1, fb:"D7 est la dominante de G. D7–G est la cadence parfaite en G majeur. C'est D7 qui confirme que l'on est en G — il contient F# (sensible de G) qui monte vers Sol." },
  { q:"La modulation vers la dominante (ex : C→G) est la plus fréquente dans la musique classique car :", opts:["Elle est la plus dramatique","G est le ton le plus proche de C — ils partagent 6 notes et plusieurs accords communs","C et G ont la même armure","Elle évite le triton"], a:1, fb:"C et G ne diffèrent que d'une note (F vs F#). C'est la modulation la plus naturelle — très fréquente chez Bach, Haydn, Mozart. La modulation vers la dominante est souvent utilisée pour la section B ou le développement." },
  { q:"La modulation vers le relatif mineur (ex : C→Am) est caractéristique de :", opts:["La cadence plagale","Nombreuses formes musicales — le trio, la section contrastante","La pédale de dominante","Le cycle des quintes"], a:1, fb:"C majeur et Am partagent exactement les mêmes notes. La modulation vers le relatif mineur crée un glissement vers une couleur plus sombre sans changer les notes de la gamme — très naturelle et très fréquente." },
  { q:"Pour moduler de C majeur vers E♭ majeur (ton éloigné), on peut utiliser :", opts:["Un accord pivot direct (ils partagent peu d'accords)","Une série d'emprunts graduels ou une modulation directe dramatique","Une basse de chaconne","Le cycle des quintes complet"], a:1, fb:"C et Eb sont éloignés (3 bémols de différence). Un pivot direct est difficile — on peut passer par des tons intermédiaires (emprunts progressifs, chromatis me) ou moduler directement pour un effet dramatique." },
  { q:"Qu'est-ce qu'un 'schéma de modulation type' ?", opts:["Un accord de pivot fixe","I–IV–V–I (en départ), pivot, V–I (en arrivée) — soit T→SD dans le départ, pivot, D→T dans l'arrivée","Deux cadences parfaites consécutives","Un changement d'armure brutal"], a:1, fb:"Schéma type : T–SD (dans la tonalité de départ) → accord pivot (réinterprété) → D–T (cadence parfaite dans la nouvelle tonalité). Le pivot est souvent une sous-dominante ou un accord neutre." },
  { q:"Pourquoi la sous-dominante est-elle souvent choisie comme accord pivot ?", opts:["Car elle est la plus grave","Car elle prépare naturellement la dominante de la nouvelle tonalité — elle est fonctionnellement en 'attente'","Car elle a toujours une quinte juste","Car elle est toujours majeure"], a:1, fb:"La sous-dominante prépare la dominante — c'est sa fonction. Utilisée comme pivot, elle se réinterprète comme SD de la nouvelle tonalité et appelle naturellement la dominante qui confirme l'arrivée." },
  { q:"La modulation peut être préparée par :", opts:["N'importe quel accord sans préparation","Une tonicisation progressive vers la nouvelle tonalité — V/V peut préparer la modulation vers V","Un accord napolitain uniquement","Une pédale de basse obligatoire"], a:1, fb:"Une tonicisation vers V (ex : D7 en C qui prépare G) peut devenir une modulation si on reste en G. Le V/V prépare si naturellement la nouvelle tonique (G) que la transition semble évidente." },
  { q:"Dans une modulation par accord pivot, combien de fonctions a l'accord pivot ?", opts:["Une seule","Deux — une dans chaque tonalité (départ et arrivée)","Trois","Aucune — il est neutre"], a:1, fb:"L'accord pivot a deux fonctions simultanées : l'une dans la tonalité de départ, l'autre dans celle d'arrivée. C'est cette double appartenance qui permet la transition sans rupture." },
  { q:"La modulation est souvent utilisée dans les formes musicales pour :", opts:["Accélérer le tempo","Créer un contraste et donner du mouvement au discours musical — sections A et B, développement","Éviter les répétitions de mélodie","Simplifier l'harmonie"], a:1, fb:"La modulation est un outil formel puissant — elle crée un contraste harmonique entre les sections d'une pièce. La forme sonate exploite systématiquement la modulation vers la dominante dans le développement." },

  // ── Accord pivot (22) ──
  { q:"Un accord pivot est :", opts:["Un accord joué très fort","Un accord appartenant simultanément à deux tonalités différentes — il assure la transition","Un accord de dominante secondaire","Un accord en deuxième renversement"], a:1, fb:"L'accord pivot est un accord qui appartient aux deux tonalités — départ et arrivée. On le joue une fois avec sa fonction de départ, puis on le réinterprète dans la nouvelle tonalité. C'est la charnière de la modulation." },
  { q:"Quelle propriété fait d'un accord un bon pivot ?", opts:["D'être majeur","D'appartenir aux deux tonalités et d'avoir une fonction naturelle dans chacune — idéalement non-cadentielle","D'être à l'état fondamental","De n'avoir aucune altération"], a:1, fb:"Un bon pivot appartient aux deux tonalités et a une fonction musicalement logique dans chacune. Il est idéalement non-cadentiel (pas la dominante ni la tonique principale) pour ne pas trop marquer la direction." },
  { q:"En modulant de C vers G, Am est un excellent pivot car :", opts:["Am est majeur dans les deux tonalités","Am est VI en C (tonique secondaire) et II en G (sous-dominante) — deux fonctions naturelles","Am est la dominante des deux","Am contient toutes les notes des deux gammes"], a:1, fb:"Am = VI en C (tonique, rôle stable) et II en G (sous-dominante, prépare D7). La réinterprétation est naturelle — Am en VI dans C glisse vers Am en II dans G, qui appelle D7–G." },
  { q:"En modulant de C vers G, Em est un pivot :", opts:["Impossible — Em n'est pas dans G","Possible — Em est III en C et VI en G, deux fonctions toniques","Très courant et cadentiel","Impossible car Em est diminué en G"], a:1, fb:"Em est III en C (tonique) et VI en G (tonique). C'est un pivot valide — Em a la même sonorité dans les deux tonalités (tonique secondaire). Il est moins courant qu'Am mais fonctionne." },
  { q:"Pourquoi évite-t-on G comme pivot en modulant de C vers G ?", opts:["G n'est pas dans C","G est la tonique d'arrivée — l'utiliser comme pivot trop tôt révèle prématurément la destination","G est toujours mineur","G crée des octaves parallèles"], a:1, fb:"G est la tonique de G majeur. Si on l'entend trop tôt comme V de C (sa fonction en C), l'oreille anticipe l'arrivée et perd la surprise. On préfère un pivot plus neutre — Am ou Em." },
  { q:"Les accords communs entre C majeur et G majeur sont :", opts:["C, Dm, Em, F, G, Am","C, Em, G, Am (et Bdim en C = Em en G)","G, D, A, E, B","F, Bb, Eb"], a:1, fb:"C majeur : C Dm Em F G7 Am Bdim. G majeur : G Am Bm C D7 Em F#dim. Accords communs : C (I en C / IV en G), Em (III en C / VI en G), Am (VI en C / II en G), G (V en C / I en G)." },
  { q:"En modulant de G vers D, Bm est un bon pivot car :", opts:["Bm est majeur dans les deux","Bm est III en G (tonique) et VI en D (tonique secondaire) — deux fonctions stables","Bm est la dominante de G","Bm n'existe pas en D"], a:1, fb:"Bm est III de G et VI de D — tonique dans les deux tonalités. C'est le pivot le plus naturel pour la modulation G→D, symétrique à Am pour C→G." },
  { q:"La progression C–Am–D7–G illustre :", opts:["Une tonicisation de Am","Une modulation de C vers G avec Am comme pivot","Une cadence rompue","Une basse de chaconne"], a:1, fb:"Am est pivot : VI en C (tonique, la progression commence en C) → II en G (sous-dominante). D7 est la dominante de G. La cadence D7–G confirme G majeur comme nouveau centre tonal." },
  { q:"En modulant de F vers C, Dm est un pivot car :", opts:["Dm est majeur dans les deux","Dm est VI en F et II en C — fonctions tonique et sous-dominante","Dm est la dominante de F","Dm n'existe pas en C"], a:1, fb:"Dm est VI de F (tonique secondaire) et II de C (sous-dominante). En modulant F→C, Dm se réinterprète et prépare G7 (V de C). La cadence G7–C confirme C." },
  { q:"Pour trouver un accord pivot, on cherche :", opts:["Un accord majeur quelconque","Les accords communs aux deux tonalités — on liste les accords de chaque gamme et on trouve les intersections","Un accord diminué","Un accord renversé"], a:1, fb:"Méthode : (1) lister tous les accords de la gamme de départ, (2) lister tous les accords de la gamme d'arrivée, (3) trouver les accords communs, (4) choisir celui avec les fonctions les plus musicales." },
  { q:"Le pivot idéal est généralement :", opts:["La tonique de la gamme de départ","Une sous-dominante ou un accord de fonction tonique secondaire — ni trop marqué ni trop instable","La dominante de la gamme d'arrivée","Un accord diminué"], a:1, fb:"Ni la tonique principale (trop marquée) ni la dominante (trop cadentielle) — le pivot idéal est un accord intermédiaire : VI ou II de départ (= II ou VI d'arrivée). Am pour C→G est l'exemple classique." },
  { q:"En C majeur, F est un accord commun à :", opts:["C majeur et G majeur","C majeur et F majeur (I de F) et Bb majeur (V de Bb)","C majeur et D mineur","C majeur et E mineur"], a:1, fb:"F (Fa majeur) est IV de C, I de F, et V de Bb. En modulant de C vers F, F serait la tonique d'arrivée — à éviter comme pivot. Vers Bb, F pourrait être un pivot (V de Bb = SD de C — rôle similaire)." },
  { q:"La notation 'pivot' dans une analyse harmonique se note souvent :", opts:["En rouge","Avec un crochet double — la même mesure annotée dans les deux tonalités (ex : [VI en C = II en G])","En 3/4","Avec un accord diminué"], a:1, fb:"L'accord pivot est annoté doublement : VI en C / II en G (ou similaire). Cette double annotation montre explicitement la réinterprétation — même accord, deux lectures fonctionnelles simultanées." },
  { q:"En modulant de Am vers C majeur, quel accord peut servir de pivot ?", opts:["G7","Em — III de C et VI de Am (les deux relatives partagent tous leurs accords)","Dm","Bdim"], a:1, fb:"Am et C sont relatifs — ils partagent exactement les mêmes 7 notes et les mêmes accords. N'importe quel accord peut être pivot. Em est souvent utilisé : III de C et VI de Am — deux fonctions toniques." },
  { q:"En modulant de C vers Eb (médiante inférieure), les accords communs sont :", opts:["Nombreux — 6 accords communs","Rares — C et Eb ne partagent que Cm (I de Cm et VI de Eb) et Gm","Aucun — modulation directe obligatoire","F et Bb seulement"], a:1, fb:"C majeur et Eb majeur ne partagent pas beaucoup d'accords diatoniques. Cm peut servir de pivot (minorisation de C → I de Cm → VI de Eb). Ou Am → VI de C / IIm de... c'est une modulation plus complexe." },
  { q:"La progression G–Em–Am–D7–G (en G majeur) montre :", opts:["Une modulation vers Am","Une cadence parfaite en G avec Am comme accord de passage","Un retour à G sans modulation — Am est II de G (sous-dominante)","Une tonicisation de D"], a:1, fb:"Pas de modulation ici — Am est simplement II de G (sous-dominante), Em est VI de G (tonique). La progression est T–T–SD–D–T en G majeur. Am n'a pas changé de tonalité." },
  { q:"En modulant de D vers A, F#m est un pivot car :", opts:["F#m est majeur dans D","F#m est III en D (tonique) et VI en A (tonique) — deux fonctions stables","F#m est la dominante de D","F#m n'existe qu'en A"], a:1, fb:"F#m est le IIIe degré de D majeur et le VIe degré de A majeur — tonique dans les deux tonalités. C'est le pivot naturel pour D→A, comme Bm l'est pour G→D et Am pour C→G." },
  { q:"Quel accord commun à C et F est un bon pivot pour moduler C→F ?", opts:["C (tonique de départ — trop marqué)","Am — VI en C et III en F (deux toniques)","G7 (dominante de C — trop cadentielle)","Bdim"], a:1, fb:"Am est VI de C (tonique) et III de F (tonique aussi). C'est un pivot neutre et naturel. Après Am en C, on peut réinterpréter Am comme III de F et partir vers C7–F pour confirmer F majeur." },
  { q:"Pour moduler de C vers Bb, on peut utiliser Dm comme pivot car :", opts:["Dm est I de Bb","Dm est II en C (sous-dominante) et III en Bb (tonique) — deux fonctions","Dm est la dominante de Bb","Dm n'est pas dans Bb"], a:1, fb:"Dm est II de C (SD) et III de Bb (tonique). En réinterprétant Dm comme III de Bb, on peut enchaîner vers F7 (V de Bb) puis Bb. La modulation C→Bb est une modulation vers la sous-dominante." },
  { q:"La modulation de C vers Am (relatif mineur) :", opts:["Nécessite beaucoup d'accords pivots","Est la plus facile — Am et C partagent tous leurs accords, n'importe quel accord peut servir de pivot","Nécessite une cadence directe","Est impossible sans modulation chromatique"], a:1, fb:"C et Am sont relatifs — mêmes notes, même armure. N'importe quel accord commun peut servir de pivot. En pratique, Em (III/C = VI/Am) ou G (V/C = VII/Am) sont courants pour cette transition." },
  { q:"La progression C–F–G7–C–Am–E7–Am montre :", opts:["Une modulation vers Am avec Am–E7–Am comme cadence parfaite en Am (E7 = V de Am harmonique)","Un emprunt de E7","Une tonicisation sans modulation","Une cadence plagale en C"], a:0, fb:"E7 est V de Am harmonique (Mi–Sol#–Si–Ré). E7–Am est une cadence parfaite en Am. Si on reste en Am après, c'est une modulation. La progression C–Am est le pivot (VI de C = I de Am), puis E7–Am confirme Am." },
  { q:"Le pivot 'Am = VI en C / II en G' signifie que :", opts:["Am change de sonorité selon la tonalité","Am garde la même sonorité (accord de La mineur) mais sa fonction harmonique change — tonique en C, sous-dominante en G","Am est joué différemment dans chaque tonalité","Am est une erreur dans une des deux tonalités"], a:1, fb:"L'accord Am (La–Do–Mi) reste identique. Seule son interprétation fonctionnelle change : dans C, c'est une alternative à la tonique (VI). Dans G, c'est un accord préparatoire vers D7 (SD). Même son, deux rôles." },

  // ── 6/4 de cadence et V7sus4 (20) ──
  { q:"Le 6/4 de cadence est :", opts:["Un accord de sixte ajoutée","Le Ier degré en deuxième renversement — la quinte est à la basse","Le Ve degré en premier renversement","Un accord de sixte napolitaine"], a:1, fb:"I6/4 = premier degré en 2e renversement (la quinte à la basse). En C : C/G (Do–Mi–Sol avec Sol à la basse). Les intervalles au-dessus de la basse sont une sixte (Mi–Sol) et une quarte (Sol–Do) — d'où le nom 6/4." },
  { q:"Pourquoi le 6/4 de cadence est-il placé juste avant la dominante ?", opts:["Par convention arbitraire","Car ses notes (quarte et sixte sur la basse) agissent comme des appoggiatures de la quinte et de la tierce de V","Car il est plus grave","Car il remplace la sous-dominante"], a:1, fb:"Le 6/4 de cadence contient Do (quarte) et Mi (sixte) au-dessus de Sol. Ces deux notes descendent conjointement vers Si (tierce de G7) et Ré (quinte de G7). C'est une double appoggiature de la dominante." },
  { q:"En C majeur, le 6/4 de cadence s'écrit :", opts:["C/E","G/B","C/G","F/C"], a:2, fb:"C/G = Do–Mi–Sol avec Sol à la basse. C'est le I en 2e renversement. Sol est la quinte de C — d'où le nom I6/4 (sixte Do–Mi et quarte Sol–Do au-dessus de la basse Sol)." },
  { q:"La résolution du 6/4 de cadence vers V7 se fait par :", opts:["Un saut de quinte","La quarte qui descend vers la tierce de V, et la sixte qui descend vers la quinte de V","Un mouvement ascendant","Un saut de tierce"], a:1, fb:"C (quarte) descend vers Si (tierce de G7). Mi (sixte) descend vers Ré (quinte de G7). Sol (basse) reste — c'est la fondamentale de G. Deux descentes conjointes : Do→Si et Mi→Ré. La basse Sol reste immobile." },
  { q:"La séquence I6/4 → V7 → I est :", opts:["Une cadence imparfaite","Une cadence parfaite renforcée — le 6/4 de cadence prépare le V7 avec plus de tension","Une cadence rompue","Une demi-cadence"], a:1, fb:"I6/4 → V7 → I est une cadence parfaite avec préparation. Le 6/4 renforce la tension avant V7 — double appoggiature qui amplifie l'attente de résolution. Très utilisé dans les concertos classiques." },
  { q:"Le V7sus4 est :", opts:["V7 avec une septième suspendue","V7 où la tierce est temporairement remplacée par une quarte (souvent la tonique)","V7 en premier renversement","V7 avec une 9e ajoutée"], a:1, fb:"V7sus4 = accord de dominante 7 avec suspension de quarte : la tierce (Si en G7) est remplacée par la quarte (Do). En G7sus4 : Sol–Do–Ré–Fa. La quarte (Do) se résout ensuite sur la tierce (Si) : V7sus4 → V7." },
  { q:"En C majeur, G7sus4 contient les notes :", opts:["Sol–Si–Ré–Fa","Sol–Do–Ré–Fa","Sol–Si–Mi–Fa","Sol–Do–Mi–Fa"], a:1, fb:"G7sus4 = Sol–Do–Ré–Fa. La tierce Si est remplacée par la quarte Do. La quarte Do descend vers Si pour donner G7 = Sol–Si–Ré–Fa. V7sus4 → V7 → I." },
  { q:"La résolution du V7sus4 vers V7 se fait par :", opts:["Un saut de quinte","La quarte (Do dans G7sus4) qui descend d'un demi-ton vers la tierce (Si dans G7)","Un mouvement ascendant","La basse qui monte"], a:1, fb:"Dans G7sus4 → G7 : Do (quarte suspendue) descend d'un demi-ton vers Si (tierce). La suspension se lève — la tension se résout vers la vraie dominante G7 avant la résolution finale sur C." },
  { q:"Le V7sus4 crée une tension plus douce que V7 car :", opts:["Il est plus grave","La quarte remplace la tierce — pas de sensible (Si) dans l'accord, moins de tension chromatique","Il est plus rapide","Il a moins de notes"], a:1, fb:"G7sus4 ne contient pas Si (la sensible de C). L'accord est moins tendu qu'un G7 complet. La suspension crée une attente élégante — quand Si arrive enfin (V7sus4 → V7), la résolution sur C est très satisfaisante." },
  { q:"La séquence SD → I6/4 → V7 → I est :", opts:["Une cadence imparfaite","Une cadence parfaite avec double préparation — SD prépare 6/4, 6/4 prépare V7","Une demi-cadence","Une cadence rompue"], a:1, fb:"SD prépare 6/4 qui prépare V7 qui résout sur I. Trois étapes de préparation croissante — chaque accord amplifie la tension avant la résolution finale. Formule classique pour les grandes cadences." },
  { q:"Le 6/4 de cadence est utilisé pour :", opts:["Commencer une phrase","Confirmer l'arrivée dans une nouvelle tonalité avant la cadence parfaite","Créer une pédale de dominante","Remplacer la sous-dominante"], a:1, fb:"Le 6/4 de cadence (I6/4 de la nouvelle tonalité) est souvent placé juste avant la cadence parfaite — il annonce fortement la résolution imminente. C'est un 'drapeau harmonique' de la nouvelle tonalité." },
  { q:"Dans un concerto classique, le 6/4 de cadence est souvent suivi de :", opts:["La mélodie principale","Un solo cadenza — la double appoggiature résout vers la dominante sur laquelle l'interprète improvise","La récapitulation directe","Un accord de napolitain"], a:1, fb:"La cadence de concerto utilise le 6/4 pour marquer le début de la cadence soliste. Le 6/4 (Sol en basse) est tenu pendant que le soliste improvise, puis l'orchestre résout V7–I à la fin." },
  { q:"Le V7sus4 est particulièrement utilisé dans :", opts:["La musique baroque uniquement","Le jazz, le post-romantique et la musique moderne — pour sa préparation élégante","La musique médiévale","Les fugues uniquement"], a:1, fb:"V7sus4 est très prisé dans le jazz (Herbie Hancock, Bill Evans), le post-romantisme (Wagner, Debussy) et la pop/rock moderne. Il offre une préparation plus colorée et moins conventionnelle que le V direct." },
  { q:"Le 6/4 de cadence est parfois appelé 'quarte et sixte' car :", opts:["Il a quatre notes et six accords","Les intervalles au-dessus de la basse sont une quarte et une sixte (depuis la basse jusqu'aux notes de l'accord)","Il dure quatre mesures","Il est en 6/4 de temps"], a:1, fb:"Au-dessus de la basse Sol : Do est une quarte (Sol→Do = 4 degrés) et Mi est une sixte (Sol→Mi = 6 degrés). Ces deux intervalles caractérisent le I6/4 = 'accord de quarte et sixte' ou '6/4 de cadence'." },
  { q:"Quelle est la différence entre I6/4 et I6 ?", opts:["Aucune différence","I6/4 = 2e renversement (quinte à la basse), I6 = 1er renversement (tierce à la basse)","I6 = 2e renversement","I6/4 a une note de plus"], a:1, fb:"I6 = premier renversement : la tierce est à la basse (C/E en C). I6/4 = deuxième renversement : la quinte est à la basse (C/G en C). La notation chiffrée 6/4 et 6 provient de la basse chiffrée baroque." },
  { q:"La séquence V7sus4 → V7 → I évoque implicitement :", opts:["Deux toniques successives","La présence du Ier et du VIIe degré dans le mouvement de voix — Do (tonique) dans sus4 descend vers Si (sensible) qui monte vers Do","Un emprunt à la dominante","Un accord napolitain"], a:1, fb:"Do (quarte suspendue dans G7sus4) descend vers Si (tierce de G7 = sensible de C). Puis Si monte vers Do (résolution finale). Le Do → Si → Do est un mouvement de suspension-sensible-résolution implicite dans la voix." },
  { q:"Pour quelle raison le 6/4 de cadence doit-il avoir la basse doublée ?", opts:["Par esthétique","Car la basse (quinte de l'accord) est le son le plus stable du I6/4 — la doubler renforce l'accord","Car la tierce est instable","Par convention uniquement"], a:1, fb:"Dans I6/4, la basse est la quinte de l'accord. La règle de doublure du 6/4 de cadence : doubler la basse (= la quinte). La quinte est la note la plus neutre — la doubler stabilise l'accord instable." },
  { q:"Après I6/4 → V7, peut-on insérer V7sus4 entre les deux ?", opts:["Non — V7sus4 doit toujours précéder V7 directement","Oui : I6/4 → V7sus4 → V7 → I est possible et crée une tension encore plus graduée","Non — le 6/4 et le sus4 s'excluent","Seulement en mineur"], a:1, fb:"La séquence I6/4 → V7sus4 → V7 → I est tout à fait valide et élaborée. Chaque étape ajoute une couche de tension : 6/4 prépare sus4, sus4 libère la quarte vers la tierce, V7 résout sur I." },
  { q:"Le V7sus4 est souvent noté :", opts:["Vsus4","V7sus4 ou V11 (la quarte = 11e en notation jazz)","Vadd4","V4/4"], a:1, fb:"V7sus4 en notation classique = V11 en notation jazz (la quarte est l'11e harmonique). G7sus4 = G11 en jazz. Les deux notations désignent le même accord : Sol–Do–Ré–Fa (sans la tierce Si)." },
  { q:"Quel compositeur a utilisé le 6/4 de cadence de manière particulièrement dramatique ?", opts:["Bach","Mozart uniquement","Rachmaninov — dans son Concerto n°2, le 6/4 crée un effet grandiose avant la résolution","Debussy uniquement"], a:2, fb:"Le Concerto pour piano n°2 de Rachmaninov est souvent cité comme exemple d'utilisation dramatique du 6/4 de cadence — la basse tenue sur Sol (quinte de C) pendant plusieurs mesures avant la résolution finale." },

  // ── Exemples et synthèse (32) ──
  { q:"La progression C–F–G7–C–Am–D7–G est une modulation vers :", opts:["F majeur","Am","G majeur — D7–G est la cadence parfaite de G","D mineur"], a:2, fb:"Am (VI en C) devient II en G. D7 (V de G) confirme la nouvelle tonalité. La cadence parfaite D7–G établit G majeur comme nouveau centre. Schéma type : T–SD–V–I (en C), pivot Am, V–I (en G)." },
  { q:"Dans la modulation C→G avec Am comme pivot, D7 joue le rôle de :", opts:["Sous-dominante de G","Dominante de G — V de G, confirme l'arrivée dans la nouvelle tonalité","Accord pivot supplémentaire","Accord de passage chromatique"], a:1, fb:"D7 = V de G. D7–G est la cadence parfaite qui confirme G majeur. D7 contient F# (sensible de G) — c'est lui qui marque définitivement l'entrée dans la nouvelle tonalité." },
  { q:"Pour moduler de G vers C, on peut utiliser :", opts:["Em comme pivot (VI en G / III en C)","F# comme pivot","B comme pivot","Uniquement une modulation directe"], a:0, fb:"Em est VI de G (tonique) et III de C (tonique). Après Am (I de Am, relatif de C) puis G7–C, ou directement Em–Am–G7–C : Em comme pivot pour G→C crée une transition naturelle vers C." },
  { q:"La modulation vers la sous-dominante (C→F) est moins fréquente que C→G car :", opts:["F est moins harmonieux","Elle donne une sensation de 'détente' — on perd une altération (F remplace F#) — plutôt que de tension","F est hors tonalité","Elle nécessite plus d'accords"], a:1, fb:"Moduler vers la dominante (C→G) ajoute F# — une tension. Moduler vers la sous-dominante (C→F) enlève la sensible et perd F# — un relâchement. Le premier crée de l'élan, le second donne une couleur plus sombre et apaisée." },
  { q:"La progression C–Em–Am–E7–Am–D7–G module de C vers :", opts:["Am","G — Em et Am sont pivots, E7–Am établit Am temporairement, D7–G confirme G","F","D"], a:1, fb:"Longue progression : C commence en C majeur. Em–Am sont diatoniques. E7–Am = tonicisation de Am (ou modulation brève en Am). D7–G = cadence parfaite en G. La modulation finale est vers G majeur." },
  { q:"En modulant de D vers A, A7 joue le rôle de :", opts:["Accord pivot","Dominante de A — V7 de A, confirme l'arrivée en A majeur","Sous-dominante de D","Accord emprunté"], a:1, fb:"A7 = V de A majeur. La cadence A7–A confirme A comme nouveau centre tonal. F#m (VI de D / III de A) ou Bm (VI de A = II de D ? non) peut servir de pivot avant A7–A." },
  { q:"La formule SD → 6/4 → V7 → I s'écrit en C majeur :", opts:["F → C/G → G7 → C","G7 → C/G → F → C","F → G7/B → C/G → G","Dm → C/G → G7 → C"], a:0, fb:"F (SD = IV de C) → C/G (6/4 de cadence = I6/4) → G7 (dominante V7) → C (tonique I). C'est la séquence complète avec 6/4 intercalé. Le C/G prépare G7 par ses appoggiatures Do→Si et Mi→Ré." },
  { q:"Le 6/4 de cadence dans une modulation est utilisé pour :", opts:["Annuler la modulation","Confirmer et ancrer solidement la nouvelle tonalité — c'est un 'drapeau harmonique'","Remplacer l'accord pivot","Créer une tonicisation"], a:1, fb:"Après l'accord pivot et la dominante secondaire, le 6/4 de cadence (I6/4 de la nouvelle tonalité) + V7 → I forment la cadence la plus affirmée possible. La nouvelle tonalité est établie sans ambiguïté." },
  { q:"En G majeur, le 6/4 de cadence est :", opts:["G/D","D/A","G/D est correct","D/F#"], a:0, fb:"6/4 de G = G/D (Sol–Si–Ré avec Ré à la basse). Le 2e renversement de G. Les intervalles au-dessus de Ré : Sol = quarte, Si = sixte. Résolution : Sol→Fa# (tierce de D7) et Si→La (quinte de D7)." },
  { q:"Quel est l'effet du V7sus4 dans une modulation ?", opts:["Il annule la modulation","Il prépare plus doucement la dominante de la nouvelle tonalité — la quarte suspendue donne une couleur de transition plus expressive","Il crée une fausse relation","Il remplace l'accord pivot"], a:1, fb:"V7sus4 dans la nouvelle tonalité précède V7 avec une tension plus douce. La suspension (quarte au lieu de tierce) retarde le plein effet de la dominante — la résolution finale est plus attendue et plus satisfaisante." },
  { q:"La progression C–Am (pivot VI/II) – D7 – G – D/F# – G suit le schéma :", opts:["T–SD–D–T en C","T–pivot–V–I en G avec 1er renversement de D pour fluidifier la basse","Deux modulations successives","Un cycle des quintes complet"], a:1, fb:"C (T en C) → Am (pivot VI/C = II/G) → D7 (V de G) → G (I de G) → D/F# (V6 de G, 1er renversement, fluidifie la basse) → G (retour I). Progression modulante C→G avec basse élaborée." },
  { q:"La modulation de C vers Am (relatif mineur) n'altère pas l'armure car :", opts:["L'armure change toujours en modulation","C et Am partagent exactement les mêmes notes — même armure (0 altération), seul le centre tonal change","L'armure n'existe pas en mineur","La modulation vers le mineur est impossible"], a:1, fb:"C majeur et Am naturel utilisent exactement les mêmes 7 notes — pas d'altération dans l'armure. La modulation est 'modale' — on change de centre sans changer les notes. Am harmonique introduit G# comme seule altération." },
  { q:"La progression Em–C–G–D7 (sans introduction) commence probablement en :", opts:["C majeur","G majeur — D7 est la dominante de G, et Em–C–G sont tous diatoniques à G","D majeur","E mineur"], a:1, fb:"Em (VI), C (IV), G (I), D7 (V) = VI–IV–I–V en G majeur. C'est une progression entièrement diatonique à G. Sans contexte précédent en C, la tonalité la plus probable est G majeur." },
  { q:"Après une modulation, comment retourner à la tonalité d'origine ?", opts:["On ne peut pas revenir","Par une nouvelle modulation — souvent avec un accord commun entre la tonalité actuelle et d'origine","Par une cadence rompue","Par une pédale de dominante obligatoire"], a:1, fb:"Le retour à la tonalité d'origine est lui-même une modulation. On peut utiliser un nouveau pivot, une modulation directe, ou une cadence enchaînée. La forme sonate utilise ce retour (récapitulation) comme moment structurel fort." },
  { q:"En D majeur, le 6/4 de cadence est :", opts:["D/A","A/E","G/D","D/F#"], a:0, fb:"6/4 de D = D/A (Ré–Fa#–La avec La à la basse). Le 2e renversement de D. La à la basse est la quinte de D. Résolution : Ré→Do# (tierce de A7) et Fa#→Mi (quinte de A7)." },
  { q:"La progression F–Dm–Am–C7–F peut être analysée comme :", opts:["Une modulation vers C avec Am comme pivot","Une progression entièrement en F majeur avec C7 = V7 de F","Une tonicisation de Am","Une basse de chaconne"], a:1, fb:"F (I), Dm (VI), Am (III), C7 (V7), F (I) = T–T–T–D–T en F majeur. C7 est la dominante de F (V7 de F). Pas de modulation — tout est diatonique à F majeur (Am est le IIIe de F)." },
  { q:"Dans Sonate en Do de Mozart, la modulation vers Sol au sein de l'exposition est confirmée par :", opts:["Un accord napolitain","D7 (V de G) suivi de G — cadence parfaite qui installe Sol comme nouveau centre","C7 (V/IV)","Une pédale de Sol"], a:1, fb:"Comme dans toute forme sonate classique, la modulation vers la dominante (G majeur) est confirmée par la cadence parfaite D7–G. C'est l'une des conventions les plus solidement établies de la musique classique." },
  { q:"Si la progression est C–Am–F–G–Em–Am–E7–Am, la modulation finale est vers :", opts:["F majeur","G majeur","Am — E7 (V de Am harmonique) – Am est la cadence parfaite de Am","Em"], a:2, fb:"E7–Am est la cadence parfaite de A mineur (E7 = V de Am harmonique). Si la progression reste en Am après, la modulation est vers Am. Le Sol# dans E7 est la sensible de La." },
  { q:"Le schéma 'I–IV–V–I (dans départ) → accord pivot → V–I (dans arrivée)' illustre :", opts:["Une tonicisation","Le schéma type de modulation par accord pivot — cadence dans le départ, pivot, cadence dans l'arrivée","Une cadence rompue","Un emprunt à l'homonyme"], a:1, fb:"C'est le schéma canonique : établir la tonalité de départ par une cadence, glisser vers le pivot, puis confirmer la nouvelle tonalité par sa propre cadence parfaite. Structure narrative claire et efficace." },
  { q:"La V7sus4 avant une cadence parfaite en G majeur s'écrit :", opts:["G7sus4–G7–C","D7sus4–D7–G","A7sus4–D7–G","D7sus4–G"], a:1, fb:"V7sus4 de G = D7sus4 (Ré–Sol–La–Do avec Sol = quarte suspendue de la tierce Fa#). D7sus4 → D7 → G. La quarte Sol descend vers Fa# (sensible de G) qui monte vers Sol (tonique)." },
  { q:"En modulant de C vers D (ton distant d'un ton entier), un pivot possible est :", opts:["Em — III de C et II de D","Bm — pas dans C","G — V de C et IV de D","F — pas dans D"], a:2, fb:"G est V de C (dominante) et IV de D (sous-dominante). G/D — fonctions différentes mais valides. Em est III de C mais Em est aussi la IIe de D (Em n'est pas diatonique à D majeur... En D majeur : D Em F#m G A Bm C#dim. Em n'est pas dans D.) G est le pivot le plus simple." },
  { q:"La séquence F–C/G–G7–C illustre :", opts:["Une modulation vers G","SD–6/4–V7–I en C — cadence parfaite avec préparation 6/4","Un emprunt à F majeur","Une tonicisation de G"], a:1, fb:"F = IV (sous-dominante de C). C/G = I6/4 (6/4 de cadence). G7 = V7 (dominante). C = I (tonique). La séquence SD–6/4–V7–I est la cadence parfaite classique avec 6/4 intercalé." },
  { q:"Quel outil permet de confirmer la nouvelle tonalité le plus efficacement ?", opts:["Un accord renversé","La cadence parfaite I6/4 → V7 → I dans la nouvelle tonalité","Un accord emprunté","Une pédale de basse"], a:1, fb:"La séquence I6/4 → V7 → I est la confirmation la plus affirmée d'une nouvelle tonalité. Le 6/4 prépare V7 avec tension maximale, puis V7 résout sur I — signal acoustique fort d'un nouveau centre tonal." },
  { q:"Dans la modulation C→G, après Am (pivot), D7 est entendu pour la première fois comme :", opts:["Un accord de C majeur","V de G — premier accord clairement appartenant à G majeur et non à C","Un accord emprunté de A mineur","Un accord de passage"], a:1, fb:"D7 contient F# — une note qui n'appartient pas à C majeur. C'est le premier accord qui signale clairement la nouvelle tonalité G. L'oreille entend F# et comprend qu'on est maintenant en G." },
  { q:"La modulation par accord pivot est dite 'enharmonique' quand :", opts:["L'accord pivot change de nom selon la tonalité","L'accord pivot est réinterprété enharmoniquement (ex : G# = Ab) permettant une modulation vers un ton éloigné","L'armure change en même temps","Le pivot est augmenté"], a:1, fb:"La modulation enharmonique utilise la même hauteur de son écrite différemment : G# = Ab. Un accord de G#m peut être réinterprété comme Abm — passant ainsi dans une tonalité très éloignée. Technique romantique avancée." },
  { q:"En Bb majeur, le 6/4 de cadence est :", opts:["Bb/F","F/C","Eb/Bb","Bb/D"], a:0, fb:"6/4 de Bb = Bb/F (Si♭–Ré–Fa avec Fa à la basse). Fa est la quinte de Bb — c'est le 2e renversement. Résolution : Si♭→La (tierce de F7) et Ré→Do (quinte de F7). Basse Fa reste immobile." },
  { q:"La modulation de C vers A majeur (tierce majeure ascendante) est :", opts:["Impossible sans modulation directe","Difficile — C et A partagent peu d'accords (Em est III de C et V de Am, pas de A majeur directement)","Simple — F est pivot","Identique à C→G"], a:1, fb:"C majeur et A majeur ne partagent que quelques accords (Em possible). Cette modulation vers la médiante majeure est moins naturelle que C→G. On peut passer par Am comme intermédiaire (C→Am→A) ou moduler par chromatis me." },
  { q:"Quelle est la notation américaine du 6/4 de cadence en C majeur ?", opts:["Cadd6","C/G","G/C","C6/4"], a:1, fb:"C/G = accord de Do majeur avec Sol à la basse. C'est la notation slash (accord/basse) standard. En C/G, le C désigne l'accord (C majeur), le G désigne la note à la basse (Sol)." },
  { q:"Un V7sus4 sans résolution vers V7 (directement vers I) crée :", opts:["Un effet standard","Un effet harmonique moderne — la quarte ne se résout pas, elle 'flotte' sur I. Très courant en jazz et pop contemporaine.","Une erreur harmonique","Une cadence plagale"], a:1, fb:"En jazz et en musique contemporaine, V7sus4 peut résoudre directement sur I sans passer par V7. La quarte non résolue reste suspendue — effet ambigu, modal. Ex : Dsus4 → G sans passer par D7." },
  { q:"La modulation par accord pivot diffère de la modulation directe car :", opts:["Elle est plus rapide","Elle est plus fluide — l'accord pivot appartient aux deux tonalités, évitant toute rupture","Elle n'utilise jamais de cadence","Elle est plus rare"], a:1, fb:"La modulation directe saute brusquement d'une tonalité à l'autre — rupture audible. La modulation par pivot glisse entre les deux sans rupture, grâce à l'accord qui appartient simultanément aux deux gammes." },
  { q:"En A majeur, le 6/4 de cadence est :", opts:["A/E","E/B","A/C#","D/A"], a:0, fb:"6/4 de A = A/E (La–Do#–Mi avec Mi à la basse). Mi est la quinte de A — 2e renversement. Résolution : La→Sol# (tierce de E7) et Do#→Si (quinte de E7). Basse Mi reste immobile." },
  { q:"Quelle est la fonction de Am dans la progression C–Am–D7–G ?", opts:["Sous-dominante de C uniquement","Pivot : VI de C (tonique) réinterprété comme II de G (sous-dominante)","Dominante de C","Accord de passage"], a:1, fb:"Am est VI de C (tonique secondaire) et II de G (sous-dominante). C'est la charnière de la modulation C→G — il glisse d'une fonction tonique stable vers une fonction préparatoire dans G, appelant D7–G." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q:"A modulation is:", opts:["A borrowed foreign chord","A lasting change of home key — the tonal center shifts","A prolonged tonicization","A change of tempo"], a:1, fb:"Modulation durably establishes a new key — it is confirmed by a perfect cadence in the new center. It is distinct from borrowing (momentary) and tonicization (brief)." },
{ q:"What condition makes a modulation 'real' (lasting)?", opts:["Using a diminished chord","Confirmation by a perfect cadence in the new key, followed by a stay","The use of inverted chords","The presence of an artificial leading tone"], a:1, fb:"A modulation is not merely a passing color — it establishes a new tonal center. To do so, a perfect cadence (V–I) in the new key confirms the arrival. Without that stay, it is a tonicization." },
{ q:"What fundamentally distinguishes a modulation from a borrowing?", opts:["Duration — modulation = lasting, borrowing = momentary","The pitch of the notes","The number of voices","The key signature alone"], a:0, fb:"A borrowing is a passing color — one returns immediately to the home key. Modulation durably shifts the tonal center — one remains in the new key for several measures." },
{ q:"Modulation by pivot chord is the most common because:", opts:["It is the fastest","It is the smoothest — the pivot chord belongs to both keys, ensuring a seamless transition","It avoids the dominant","It requires no cadence"], a:1, fb:"The pivot chord belongs simultaneously to the departing and arriving key. It is reinterpreted (same chord, new function) — the transition is therefore imperceptible, without rupture." },
{ q:"To confirm arrival in a new key, one uses:", opts:["An inverted chord","A perfect cadence (V–I) in the new key","A Neapolitan sixth chord","A tonic pedal"], a:1, fb:"The perfect cadence in the new key — V (in root position) → I (in root position) — is the strongest signal that the tonal center has changed. Without it, the modulation remains ambiguous." },
{ q:"Closely related keys are preferred for modulations because:", opts:["They have fewer notes","They share many chords — pivots abound, the transition is smooth","They are lower in pitch","They use fewer accidentals"], a:1, fb:"Closely related keys = 6–7 common notes. The more notes and chords two keys share, the more pivot options there are and the smoother the modulation. Distant keys require more abrupt transitions." },
{ q:"A direct modulation (without pivot) creates:", opts:["A very smooth transition","A sudden rupture — theatrical or dramatic effect","An imperfect cadence","A harmonic delay"], a:1, fb:"Direct modulation (without a transitional chord) jumps abruptly from one key to another. This effect can be intentional — to mark a dramatic change — but it remains a stylistic exception." },
{ q:"The tonic of the destination key is generally avoided as a pivot because:", opts:["It is always diminished","It is too marked — hearing the tonic of the new key before the cadence weakens the surprise of the arrival","It does not belong to the departing scale","It creates parallel octaves"], a:1, fb:"If one hears the tonic of G (G major) too early as a diatonic chord of C (V of C), the ear anticipates the arrival. The ideal pivot is neutral — it does not too clearly foreshadow the destination." },
{ q:"How long must one remain in the new key to validate a modulation?", opts:["A single chord suffices","At least one perfect cadence — several measures preferably","Exactly 4 measures","One octave in duration"], a:1, fb:"A modulation is only validated if one stays in the new key. A single chord of the new key is a tonicization. At minimum a perfect cadence is required, ideally several measures." },
{ q:"In the progression C–F–G7–C–Am–D7–G, the modulation from C to G is confirmed by:", opts:["Am","D7","G — the final chord","The presence of F# in D7"], a:1, fb:"D7 is the dominant of G. D7–G is the perfect cadence in G major. It is D7 that confirms we are in G — it contains F# (the leading tone of G) which rises toward Sol." },
{ q:"Modulation to the dominant (e.g. C→G) is the most common in classical music because:", opts:["It is the most dramatic","G is the closest key to C — they share 6 notes and several common chords","C and G have the same key signature","It avoids the tritone"], a:1, fb:"C and G differ by only one note (F vs F#). It is the most natural modulation — very common in Bach, Haydn, Mozart. Modulation to the dominant is often used for the B section or development." },
{ q:"Modulation to the relative minor (e.g. C→Am) is characteristic of:", opts:["The plagal cadence","Many musical forms — the trio, the contrasting section","The dominant pedal","The cycle of fifths"], a:1, fb:"C major and Am share exactly the same notes. Modulation to the relative minor creates a shift toward a darker color without changing the scale tones — very natural and very common." },
{ q:"To modulate from C major to E♭ major (a distant key), one can use:", opts:["A direct pivot chord (they share few chords)","A series of gradual borrowings or a dramatic direct modulation","A chaconne bass","The complete cycle of fifths"], a:1, fb:"C and Eb are distant (3 flats apart). A direct pivot is difficult — one can pass through intermediate keys (progressive borrowings, chromaticism) or modulate directly for a dramatic effect." },
{ q:"What is a 'typical modulation scheme'?", opts:["A fixed pivot chord","I–IV–V–I (at departure), pivot, V–I (at arrival) — i.e. T→SD in the departure, pivot, D→T in the arrival","Two consecutive perfect cadences","An abrupt key signature change"], a:1, fb:"Typical scheme: T–SD (in the departing key) → pivot chord (reinterpreted) → D–T (perfect cadence in the new key). The pivot is often a subdominant or a neutral chord." },
{ q:"Why is the subdominant often chosen as a pivot chord?", opts:["Because it is the lowest","Because it naturally prepares the dominant of the new key — it is functionally in 'expectation'","Because it always has a perfect fifth","Because it is always major"], a:1, fb:"The subdominant prepares the dominant — that is its function. Used as a pivot, it is reinterpreted as SD of the new key and naturally calls the dominant that confirms the arrival." },
{ q:"A modulation can be prepared by:", opts:["Any chord without preparation","A progressive tonicization toward the new key — V/V can prepare modulation to V","A Neapolitan chord only","A mandatory bass pedal"], a:1, fb:"A tonicization toward V (e.g. D7 in C preparing G) can become a modulation if one stays in G. V/V prepares the new tonic (G) so naturally that the transition seems inevitable." },
{ q:"In a modulation by pivot chord, how many functions does the pivot chord have?", opts:["Only one","Two — one in each key (departure and arrival)","Three","None — it is neutral"], a:1, fb:"The pivot chord has two simultaneous functions: one in the departing key, the other in the arriving key. It is this double membership that allows a seamless transition." },
{ q:"Modulation is often used in musical forms to:", opts:["Speed up the tempo","Create contrast and give momentum to the musical discourse — sections A and B, development","Avoid melodic repetition","Simplify the harmony"], a:1, fb:"Modulation is a powerful formal tool — it creates harmonic contrast between the sections of a piece. Sonata form systematically exploits modulation to the dominant in the development." },

{ q:"A pivot chord is:", opts:["A chord played very loudly","A chord belonging simultaneously to two different keys — it ensures the transition","A secondary dominant chord","A chord in second inversion"], a:1, fb:"The pivot chord is a chord that belongs to both keys — departure and arrival. It is played once with its departing function, then reinterpreted in the new key. It is the hinge of the modulation." },
{ q:"What property makes a chord a good pivot?", opts:["Being major","Belonging to both keys and having a natural function in each — ideally non-cadential","Being in root position","Having no accidentals"], a:1, fb:"A good pivot belongs to both keys and has a musically logical function in each. It is ideally non-cadential (not the main dominant or tonic) so as not to overly signal the direction." },
{ q:"When modulating from C to G, Am is an excellent pivot because:", opts:["Am is major in both keys","Am is VI in C (secondary tonic) and II in G (subdominant) — two natural functions","Am is the dominant of both","Am contains all the notes of both scales"], a:1, fb:"Am = VI in C (tonic, stable role) and II in G (subdominant, prepares D7). The reinterpretation is natural — Am as VI in C slides to Am as II in G, which calls D7–G." },
{ q:"When modulating from C to G, Em is a pivot:", opts:["Impossible — Em is not in G","Possible — Em is III in C and VI in G, two tonic functions","Very common and cadential","Impossible because Em is diminished in G"], a:1, fb:"Em is III in C (tonic) and VI in G (tonic). It is a valid pivot — Em has the same sound in both keys (secondary tonic). It is less common than Am but works." },
{ q:"Why is G avoided as a pivot when modulating from C to G?", opts:["G is not in C","G is the destination tonic — using it as a pivot too early prematurely reveals the destination","G is always minor","G creates parallel octaves"], a:1, fb:"G is the tonic of G major. If heard too early as V of C (its function in C), the ear anticipates the arrival and loses the surprise. A more neutral pivot — Am or Em — is preferred." },
{ q:"The chords common to C major and G major are:", opts:["C, Dm, Em, F, G, Am","C, Em, G, Am (and Bdim in C = Em in G)","G, D, A, E, B","F, Bb, Eb"], a:1, fb:"C major: C Dm Em F G7 Am Bdim. G major: G Am Bm C D7 Em F#dim. Common chords: C (I in C / IV in G), Em (III in C / VI in G), Am (VI in C / II in G), G (V in C / I in G)." },
{ q:"When modulating from G to D, Bm is a good pivot because:", opts:["Bm is major in both","Bm is III in G (tonic) and VI in D (secondary tonic) — two stable functions","Bm is the dominant of G","Bm does not exist in D"], a:1, fb:"Bm is III of G and VI of D — tonic in both keys. It is the most natural pivot for the G→D modulation, symmetrical to Am for C→G." },
{ q:"The progression C–Am–D7–G illustrates:", opts:["A tonicization of Am","A modulation from C to G with Am as pivot","A deceptive cadence","A chaconne bass"], a:1, fb:"Am is pivot: VI in C (tonic, the progression begins in C) → II in G (subdominant). D7 is the dominant of G. The cadence D7–G confirms G major as the new tonal center." },
{ q:"When modulating from F to C, Dm is a pivot because:", opts:["Dm is major in both","Dm is VI in F and II in C — tonic and subdominant functions","Dm is the dominant of F","Dm does not exist in C"], a:1, fb:"Dm is VI of F (secondary tonic) and II of C (subdominant). Modulating F→C, Dm is reinterpreted and prepares G7 (V of C). The cadence G7–C confirms C." },
{ q:"To find a pivot chord, one looks for:", opts:["Any major chord","The chords common to both keys — list the chords of each scale and find the intersections","A diminished chord","An inverted chord"], a:1, fb:"Method: (1) list all chords of the departing scale, (2) list all chords of the arriving scale, (3) find common chords, (4) choose the one with the most musical functions." },
{ q:"The ideal pivot is generally:", opts:["The tonic of the departing scale","A subdominant or secondary tonic chord — neither too marked nor too unstable","The dominant of the arriving scale","A diminished chord"], a:1, fb:"Neither the main tonic (too marked) nor the dominant (too cadential) — the ideal pivot is an intermediate chord: VI or II of departure (= II or VI of arrival). Am for C→G is the classic example." },
{ q:"In C major, F is a chord common to:", opts:["C major and G major","C major and F major (I of F) and Bb major (V of Bb)","C major and D minor","C major and E minor"], a:1, fb:"F (F major) is IV of C, I of F, and V of Bb. Modulating from C to F, F would be the destination tonic — to avoid as pivot. Toward Bb, F could be a pivot (V of Bb — similar role to SD of C)." },
{ q:"The notation 'pivot' in harmonic analysis is often written:", opts:["In red","With a double bracket — the same measure annotated in both keys (e.g. [VI in C = II in G])","In 3/4","With a diminished chord"], a:1, fb:"The pivot chord is annotated doubly: VI in C / II in G (or similar). This double annotation explicitly shows the reinterpretation — same chord, two simultaneous functional readings." },
{ q:"When modulating from Am to C major, which chord can serve as a pivot?", opts:["G7","Em — III of C and VI of Am (the two relatives share all their chords)","Dm","Bdim"], a:1, fb:"Am and C are relative — they share exactly the same 7 notes and the same chords. Any chord can be a pivot. Em is often used: III of C and VI of Am — two tonic functions." },
{ q:"When modulating from C to Eb (lower mediant), the common chords are:", opts:["Numerous — 6 common chords","Rare — C and Eb share only Cm (I of Cm and VI of Eb) and Gm","None — direct modulation required","F and Bb only"], a:1, fb:"C major and Eb major share few diatonic chords. Cm can serve as pivot (minorization of C → I of Cm → VI of Eb). This is a more complex modulation." },
{ q:"The progression G–Em–Am–D7–G (in G major) shows:", opts:["A modulation toward Am","A perfect cadence in G with Am as a passing chord","A return to G without modulation — Am is II of G (subdominant)","A tonicization of D"], a:1, fb:"No modulation here — Am is simply II of G (subdominant), Em is VI of G (tonic). The progression is T–T–SD–D–T in G major. Am has not changed the key." },
{ q:"When modulating from D to A, F#m is a pivot because:", opts:["F#m is major in D","F#m is III in D (tonic) and VI in A (tonic) — two stable functions","F#m is the dominant of D","F#m only exists in A"], a:1, fb:"F#m is the third degree of D major and the sixth degree of A major — tonic in both keys. It is the natural pivot for D→A, just as Bm is for G→D and Am for C→G." },
{ q:"Which chord common to C and F is a good pivot for modulating C→F?", opts:["C (departing tonic — too marked)","Am — VI in C and III in F (two tonics)","G7 (dominant of C — too cadential)","Bdim"], a:1, fb:"Am is VI of C (tonic) and III of F (tonic as well). It is a neutral and natural pivot. After Am in C, one can reinterpret Am as III of F and move toward C7–F to confirm F major." },
{ q:"To modulate from C to Bb, Dm can be used as a pivot because:", opts:["Dm is I of Bb","Dm is II in C (subdominant) and III in Bb (tonic) — two functions","Dm is the dominant of Bb","Dm is not in Bb"], a:1, fb:"Dm is II of C (SD) and III of Bb (tonic). By reinterpreting Dm as III of Bb, one can move to F7 (V of Bb) then Bb. The modulation C→Bb is a modulation toward the subdominant." },
{ q:"Modulation from C to Am (relative minor):", opts:["Requires many pivot chords","Is the easiest — Am and C share all their chords, any chord can serve as pivot","Requires a direct cadence","Is impossible without chromatic modulation"], a:1, fb:"C and Am are relative — same notes, same key signature. Any common chord can serve as pivot. In practice, Em (III/C = VI/Am) or G (V/C = VII/Am) are common for this transition." },
{ q:"The progression C–F–G7–C–Am–E7–Am shows:", opts:["A modulation to Am with Am–E7–Am as a perfect cadence in Am (E7 = V of harmonic Am)","A borrowing of E7","A tonicization without modulation","A plagal cadence in C"], a:0, fb:"E7 is V of harmonic A minor (E–G#–B–D). E7–Am is a perfect cadence in A minor. If the progression stays in Am afterward, it is a modulation. The progression C–Am is the pivot (VI of C = I of Am), then E7–Am confirms Am." },
{ q:"The pivot 'Am = VI in C / II in G' means that:", opts:["Am changes its sound depending on the key","Am retains the same sound (A minor chord) but its harmonic function changes — tonic in C, subdominant in G","Am is played differently in each key","Am is an error in one of the two keys"], a:1, fb:"The chord Am (A–C–E) remains identical. Only its functional interpretation changes: in C it is an alternative to the tonic (VI). In G it is a preparatory chord toward D7 (SD). Same sound, two roles." },

{ q:"The cadential 6/4 is:", opts:["An added sixth chord","The first degree in second inversion — the fifth is in the bass","The fifth degree in first inversion","A Neapolitan sixth chord"], a:1, fb:"I6/4 = first degree in 2nd inversion (fifth in the bass). In C: C/G (C–E–G with G in the bass). The intervals above the bass are a sixth (E–G) and a fourth (G–C) — hence the name 6/4." },
{ q:"Why is the cadential 6/4 placed just before the dominant?", opts:["By arbitrary convention","Because its notes (fourth and sixth above the bass) act as appoggiaturas of the fifth and third of V","Because it is lower","Because it replaces the subdominant"], a:1, fb:"The cadential 6/4 contains C (fourth) and E (sixth) above G. These two notes descend stepwise to B (third of G7) and D (fifth of G7). It is a double appoggiatura of the dominant." },
{ q:"In C major, the cadential 6/4 is written:", opts:["C/E","G/B","C/G","F/C"], a:2, fb:"C/G = C–E–G with G in the bass. This is I in 2nd inversion. G is the fifth of C — hence the name I6/4 (sixth C–E and fourth G–C above the bass G)." },
{ q:"The resolution of the cadential 6/4 to V7 occurs by:", opts:["A leap of a fifth","The fourth descending to the third of V, and the sixth descending to the fifth of V","An ascending motion","A leap of a third"], a:1, fb:"C (fourth) descends to B (third of G7). E (sixth) descends to D (fifth of G7). G (bass) stays — it is the root of G. Two stepwise descents: C→B and E→D. The bass G remains stationary." },
{ q:"The sequence I6/4 → V7 → I is:", opts:["An imperfect cadence","A reinforced perfect cadence — the 6/4 prepares V7 with greater tension","A deceptive cadence","A half cadence"], a:1, fb:"I6/4 → V7 → I is a perfect cadence with preparation. The 6/4 reinforces the tension before V7 — a double appoggiatura that amplifies the expectation of resolution. Widely used in classical concertos." },
{ q:"The V7sus4 is:", opts:["V7 with a suspended seventh","V7 where the third is temporarily replaced by a fourth (often the tonic)","V7 in first inversion","V7 with an added 9th"], a:1, fb:"V7sus4 = dominant 7 chord with suspended fourth: the third (B in G7) is replaced by the fourth (C). In G7sus4: G–C–D–F. The fourth (C) then resolves to the third (B): V7sus4 → V7." },
{ q:"In C major, G7sus4 contains the notes:", opts:["G–B–D–F","G–C–D–F","G–B–E–F","G–C–E–F"], a:1, fb:"G7sus4 = G–C–D–F. The third B is replaced by the fourth C. The fourth C descends to B to give G7 = G–B–D–F. V7sus4 → V7 → I." },
{ q:"The resolution of V7sus4 to V7 occurs by:", opts:["A leap of a fifth","The fourth (C in G7sus4) descending by a half step to the third (B in G7)","An ascending motion","The bass moving up"], a:1, fb:"In G7sus4 → G7: C (suspended fourth) descends by a half step to B (third). The suspension lifts — the tension resolves to the true dominant G7 before the final resolution on C." },
{ q:"V7sus4 creates a softer tension than V7 because:", opts:["It is lower in pitch","The fourth replaces the third — no leading tone (B) in the chord, less chromatic tension","It is faster","It has fewer notes"], a:1, fb:"G7sus4 does not contain B (the leading tone of C). The chord is less tense than a full G7. The suspension creates an elegant expectation — when B finally arrives (V7sus4 → V7), the resolution on C is very satisfying." },
{ q:"The sequence SD → I6/4 → V7 → I is:", opts:["An imperfect cadence","A perfect cadence with double preparation — SD prepares 6/4, 6/4 prepares V7","A half cadence","A deceptive cadence"], a:1, fb:"SD prepares 6/4 which prepares V7 which resolves on I. Three steps of increasing preparation — each chord amplifies the tension before the final resolution. Classic formula for grand cadences." },
{ q:"The cadential 6/4 is used to:", opts:["Begin a phrase","Firmly confirm the arrival in a new key before the perfect cadence","Create a dominant pedal","Replace the subdominant"], a:1, fb:"The cadential 6/4 (I6/4 of the new key) is often placed just before the perfect cadence — it strongly announces the imminent resolution. It is a 'harmonic flag' of the new key." },
{ q:"In a classical concerto, the cadential 6/4 is often followed by:", opts:["The main melody","A solo cadenza — the double appoggiatura resolves to the dominant over which the performer improvises","The direct recapitulation","A Neapolitan chord"], a:1, fb:"The concerto cadence uses the 6/4 to mark the beginning of the solo cadenza. The 6/4 (G in the bass) is sustained while the soloist improvises, then the orchestra resolves V7–I at the end." },
{ q:"V7sus4 is particularly used in:", opts:["Baroque music only","Jazz, post-romanticism, and modern music — for its elegant preparation","Medieval music","Fugues only"], a:1, fb:"V7sus4 is highly prized in jazz (Herbie Hancock, Bill Evans), post-romanticism (Wagner, Debussy), and modern pop/rock. It offers a more colorful and less conventional preparation than a direct V." },
{ q:"The cadential 6/4 is sometimes called 'fourth and sixth' because:", opts:["It has four notes and six chords","The intervals above the bass are a fourth and a sixth (from the bass up to the chord tones)","It lasts four measures","It is in 6/4 time"], a:1, fb:"Above the bass G: C is a fourth (G→C = 4 scale degrees) and E is a sixth (G→E = 6 scale degrees). These two intervals characterize the I6/4 = 'fourth and sixth chord' or 'cadential 6/4'." },
{ q:"What is the difference between I6/4 and I6?", opts:["No difference","I6/4 = 2nd inversion (fifth in the bass), I6 = 1st inversion (third in the bass)","I6 = 2nd inversion","I6/4 has one more note"], a:1, fb:"I6 = first inversion: the third is in the bass (C/E in C). I6/4 = second inversion: the fifth is in the bass (C/G in C). The figured bass notation 6/4 and 6 derives from Baroque thoroughbass." },
{ q:"The sequence V7sus4 → V7 → I implicitly evokes:", opts:["Two successive tonics","The presence of the first and seventh degree in the voice leading — C (tonic) in sus4 descends to B (leading tone) which rises to C","A borrowing from the dominant","A Neapolitan chord"], a:1, fb:"C (suspended fourth in G7sus4) descends to B (third of G7 = leading tone of C). Then B rises to C (final resolution). The C → B → C is an implicit suspension–leading tone–resolution motion in the voice." },
{ q:"Why must the bass of the cadential 6/4 be doubled?", opts:["For aesthetic reasons","Because the bass (fifth of the chord) is the most stable tone of the I6/4 — doubling it reinforces the unstable chord","Because the third is unstable","By convention only"], a:1, fb:"In I6/4, the bass is the fifth of the chord. The doubling rule for the cadential 6/4: double the bass (= the fifth). The fifth is the most neutral note — doubling it stabilizes the unstable chord." },
{ q:"After I6/4 → V7, can V7sus4 be inserted between the two?", opts:["No — V7sus4 must always directly precede V7","Yes: I6/4 → V7sus4 → V7 → I is possible and creates an even more gradual tension","No — the 6/4 and sus4 are mutually exclusive","Only in minor"], a:1, fb:"The sequence I6/4 → V7sus4 → V7 → I is entirely valid and elaborate. Each step adds a layer of tension: 6/4 prepares sus4, sus4 releases the fourth to the third, V7 resolves on I." },
{ q:"V7sus4 is often notated:", opts:["Vsus4","V7sus4 or V11 (the fourth = 11th in jazz notation)","Vadd4","V4/4"], a:1, fb:"V7sus4 in classical notation = V11 in jazz notation (the fourth is the 11th harmonic). G7sus4 = G11 in jazz. Both notations refer to the same chord: G–C–D–F (without the third B)." },
{ q:"Which composer used the cadential 6/4 in a particularly dramatic way?", opts:["Bach","Mozart only","Rachmaninoff — in his Concerto No. 2, the 6/4 creates a grandiose effect before the resolution","Debussy only"], a:2, fb:"Rachmaninoff's Piano Concerto No. 2 is often cited as an example of dramatic use of the cadential 6/4 — the bass held on G (fifth of C) for several measures before the final resolution." },

{ q:"The progression C–F–G7–C–Am–D7–G is a modulation to:", opts:["F major","Am","G major — D7–G is the perfect cadence of G","D minor"], a:2, fb:"Am (VI in C) becomes II in G. D7 (V of G) confirms the new key. The perfect cadence D7–G establishes G major as the new center. Typical scheme: T–SD–V–I (in C), pivot Am, V–I (in G)." },
{ q:"In the modulation C→G with Am as pivot, D7 plays the role of:", opts:["Subdominant of G","Dominant of G — V of G, confirms arrival in the new key","Additional pivot chord","Chromatic passing chord"], a:1, fb:"D7 = V of G. D7–G is the perfect cadence that confirms G major. D7 contains F# (leading tone of G) — it is this chord that definitively marks entry into the new key." },
{ q:"To modulate from G to C, one can use:", opts:["Em as pivot (VI in G / III in C)","F# as pivot","B as pivot","Only a direct modulation"], a:0, fb:"Em is VI of G (tonic) and III of C (tonic). After Am (I of Am, relative of C) then G7–C, or directly Em–Am–G7–C: Em as pivot for G→C creates a natural transition toward C." },
{ q:"Modulation to the subdominant (C→F) is less common than C→G because:", opts:["F is less harmonious","It gives a sense of 'relaxation' — one loses an accidental (F replaces F#) — rather than tension","F is outside the key","It requires more chords"], a:1, fb:"Modulating to the dominant (C→G) adds F# — a tension. Modulating to the subdominant (C→F) removes the leading tone and loses F# — a release. The former creates momentum, the latter gives a darker, more peaceful color." },
{ q:"The progression C–Em–Am–E7–Am–D7–G modulates from C to:", opts:["Am","G — Em and Am are pivots, E7–Am temporarily establishes Am, D7–G confirms G","F","D"], a:1, fb:"Long progression: C begins in C major. Em–Am are diatonic. E7–Am = tonicization of Am (or brief modulation to Am). D7–G = perfect cadence in G. The final modulation is to G major." },
{ q:"When modulating from D to A, A7 plays the role of:", opts:["Pivot chord","Dominant of A — V7 of A, confirms arrival in A major","Subdominant of D","Borrowed chord"], a:1, fb:"A7 = V of A major. The cadence A7–A confirms A as the new tonal center. F#m (VI of D / III of A) can serve as pivot before A7–A." },
{ q:"The formula SD → 6/4 → V7 → I written in C major is:", opts:["F → C/G → G7 → C","G7 → C/G → F → C","F → G7/B → C/G → G","Dm → C/G → G7 → C"], a:0, fb:"F (SD = IV of C) → C/G (cadential 6/4 = I6/4) → G7 (dominant V7) → C (tonic I). This is the complete sequence with the 6/4 inserted. C/G prepares G7 through its appoggiaturas C→B and E→D." },
{ q:"The cadential 6/4 in a modulation is used to:", opts:["Cancel the modulation","Confirm and firmly anchor the new key — it is a 'harmonic flag'","Replace the pivot chord","Create a tonicization"], a:1, fb:"After the pivot chord and secondary dominant, the cadential 6/4 (I6/4 of the new key) + V7 → I form the most definitive possible cadence. The new key is established without any ambiguity." },
];

const questionsEs: Question[] = [{ q:"Una modulación es:", opts:["Un préstamo de acorde extraño","Un cambio duradero de tonalidad principal — el centro tonal se desplaza","Una tonicización prolongada","Un cambio de tempo"], a:1, fb:"La modulación instala duraderamente una nueva tonalidad — se confirma mediante una cadencia perfecta en el nuevo centro. Se distingue del préstamo (momentáneo) y de la tonicización (breve)." },
{ q:"¿Qué condición hace que una modulación sea 'real' (duradera)?", opts:["Usar un acorde disminuido","La confirmación mediante una cadencia perfecta en la nueva tonalidad, seguida de una permanencia","El uso de acordes invertidos","La presencia de una sensible artificial"], a:1, fb:"Una modulación no es un simple color pasajero — instala un nuevo centro tonal. Para ello, una cadencia perfecta (V–I) en el nuevo tono confirma la llegada. Sin esa permanencia, es una tonicización." },
{ q:"¿Qué distingue fundamentalmente una modulación de un préstamo?", opts:["La duración — modulación = duradera, préstamo = momentáneo","La altura de las notas","El número de voces","La armadura únicamente"], a:0, fb:"Un préstamo es un color pasajero — se regresa inmediatamente a la tonalidad principal. La modulación desplaza duraderamente el centro tonal — se permanece en la nueva tonalidad durante varios compases." },
{ q:"La modulación por acorde pivote es la más frecuente porque:", opts:["Es la más rápida","Es la más fluida — el acorde pivote pertenece a las dos tonalidades, asegurando una transición sin ruptura","Evita la dominante","No requiere cadencia"], a:1, fb:"El acorde pivote pertenece simultáneamente a la tonalidad de partida y a la de llegada. Se reinterpreta (mismo acorde, nueva función) — la transición es imperceptible, sin ruptura." },
{ q:"Para confirmar la llegada a una nueva tonalidad, se utiliza:", opts:["Un acorde invertido","Una cadencia perfecta (V–I) en el nuevo tono","Un acorde de sexta napolitana","Un pedal de tónica"], a:1, fb:"La cadencia perfecta en la nueva tonalidad — V (en estado fundamental) → I (en estado fundamental) — es la señal más fuerte de que el centro tonal ha cambiado. Sin ella, la modulación permanece ambigua." },
{ q:"Los tonos vecinos son preferidos para las modulaciones porque:", opts:["Tienen menos notas","Comparten numerosos acordes — los pivotes abundan, la transición es suave","Son más graves","Usan menos alteraciones"], a:1, fb:"Tonos vecinos = 6-7 notas comunes. Cuantas más notas y acordes compartan las dos tonalidades, más pivotes posibles hay y más fluida es la modulación. Los tonos lejanos requieren transiciones más abruptas." },
{ q:"Una modulación directa (sin pivote) crea:", opts:["Una transición muy suave","Una ruptura brusca — efecto teatral o dramático","Una cadencia imperfecta","Un retardo armónico"], a:1, fb:"La modulación directa (sin acorde de transición) salta bruscamente de una tonalidad a otra. Este efecto puede ser buscado — para marcar un cambio dramático — pero sigue siendo una excepción estilística." },
{ q:"La tónica de la tonalidad de llegada generalmente se evita como pivote porque:", opts:["Siempre es disminuida","Está demasiado marcada — escuchar la tónica del nuevo tono antes de la cadencia debilita la sorpresa de la llegada","No pertenece a la escala de partida","Crea octavas paralelas"], a:1, fb:"Si se escucha la tónica de G (G mayor) demasiado pronto como acorde diatónico de C (V de C), el oído anticipa la llegada. El acorde pivote ideal es neutro — no prefigura demasiado claramente el destino." },
{ q:"¿Cuánto tiempo hay que permanecer en la nueva tonalidad para validar una modulación?", opts:["Un solo acorde es suficiente","Al menos una cadencia perfecta — preferiblemente varios compases","Exactamente 4 compases","Una octava de duración"], a:1, fb:"Una modulación solo se valida si se permanece en la nueva tonalidad. Un solo acorde de la nueva tonalidad es una tonicización. Se necesita como mínimo una cadencia perfecta, idealmente varios compases." },
{ q:"En la progresión C–F–G7–C–Am–D7–G, la modulación de C hacia G se confirma por:", opts:["Am","D7","G — el acorde final","La presencia de F# en D7"], a:1, fb:"D7 es la dominante de G. D7–G es la cadencia perfecta en G mayor. Es D7 quien confirma que estamos en G — contiene F# (sensible de G) que asciende hacia Sol." },
{ q:"La modulación hacia la dominante (ej.: C→G) es la más frecuente en la música clásica porque:", opts:["Es la más dramática","G es el tono más cercano a C — comparten 6 notas y varios acordes comunes","C y G tienen la misma armadura","Evita el tritono"], a:1, fb:"C y G solo difieren en una nota (F vs F#). Es la modulación más natural — muy frecuente en Bach, Haydn, Mozart. La modulación hacia la dominante se usa a menudo para la sección B o el desarrollo." },
{ q:"La modulación hacia el relativo menor (ej.: C→Am) es característica de:", opts:["La cadencia plagal","Numerosas formas musicales — el trío, la sección contrastante","El pedal de dominante","El ciclo de quintas"], a:1, fb:"C mayor y Am comparten exactamente las mismas notas. La modulación hacia el relativo menor crea un deslizamiento hacia un color más oscuro sin cambiar las notas de la escala — muy natural y muy frecuente." },
{ q:"Para modular de C mayor hacia E♭ mayor (tono lejano), se puede utilizar:", opts:["Un acorde pivote directo (comparten pocos acordes)","Una serie de préstamos graduales o una modulación directa dramática","Un bajo de chacona","El ciclo completo de quintas"], a:1, fb:"C y Eb están alejados (3 bemoles de diferencia). Un pivote directo es difícil — se puede pasar por tonos intermedios (préstamos progresivos, cromatismo) o modular directamente para un efecto dramático." },
{ q:"¿Qué es un 'esquema de modulación tipo'?", opts:["Un acorde pivote fijo","I–IV–V–I (en partida), pivote, V–I (en llegada) — es decir T→SD en la partida, pivote, D→T en la llegada","Dos cadencias perfectas consecutivas","Un cambio brusco de armadura"], a:1, fb:"Esquema tipo: T–SD (en la tonalidad de partida) → acorde pivote (reinterpretado) → D–T (cadencia perfecta en la nueva tonalidad). El pivote es a menudo una subdominante o un acorde neutro." },
{ q:"¿Por qué la subdominante se elige frecuentemente como acorde pivote?", opts:["Porque es la más grave","Porque prepara naturalmente la dominante de la nueva tonalidad — está funcionalmente en 'espera'","Porque siempre tiene una quinta justa","Porque siempre es mayor"], a:1, fb:"La subdominante prepara la dominante — esa es su función. Usada como pivote, se reinterpreta como SD de la nueva tonalidad y llama naturalmente a la dominante que confirma la llegada." },
{ q:"La modulación puede prepararse mediante:", opts:["Cualquier acorde sin preparación","Una tonicización progresiva hacia la nueva tonalidad — V/V puede preparar la modulación hacia V","Un acorde napolitano únicamente","Un pedal de bajo obligatorio"], a:1, fb:"Una tonicización hacia V (ej.: D7 en C que prepara G) puede convertirse en modulación si se permanece en G. El V/V prepara tan naturalmente la nueva tónica (G) que la transición parece evidente." },
{ q:"En una modulación por acorde pivote, ¿cuántas funciones tiene el acorde pivote?", opts:["Una sola","Dos — una en cada tonalidad (partida y llegada)","Tres","Ninguna — es neutro"], a:1, fb:"El acorde pivote tiene dos funciones simultáneas: una en la tonalidad de partida, otra en la de llegada. Esta doble pertenencia es lo que permite la transición sin ruptura." },
{ q:"La modulación se usa frecuentemente en las formas musicales para:", opts:["Acelerar el tempo","Crear contraste y dar movimiento al discurso musical — secciones A y B, desarrollo","Evitar repeticiones de melodía","Simplificar la armonía"], a:1, fb:"La modulación es una herramienta formal poderosa — crea un contraste armónico entre las secciones de una pieza. La forma sonata explota sistemáticamente la modulación hacia la dominante en el desarrollo." },
{ q:"Un acorde pivote es:", opts:["Un acorde tocado muy fuerte","Un acorde que pertenece simultáneamente a dos tonalidades diferentes — asegura la transición","Un acorde de dominante secundaria","Un acorde en segunda inversión"], a:1, fb:"El acorde pivote es un acorde que pertenece a las dos tonalidades — partida y llegada. Se toca una vez con su función de partida, luego se reinterpreta en la nueva tonalidad. Es la bisagra de la modulación." },
{ q:"¿Qué propiedad hace de un acorde un buen pivote?", opts:["Ser mayor","Pertenecer a las dos tonalidades y tener una función natural en cada una — idealmente no cadencial","Estar en estado fundamental","No tener ninguna alteración"], a:1, fb:"Un buen pivote pertenece a las dos tonalidades y tiene una función musicalmente lógica en cada una. Idealmente es no cadencial (ni la dominante ni la tónica principal) para no marcar demasiado la dirección." },
{ q:"Al modular de C hacia G, Am es un excelente pivote porque:", opts:["Am es mayor en las dos tonalidades","Am es VI en C (tónica secundaria) y II en G (subdominante) — dos funciones naturales","Am es la dominante de las dos","Am contiene todas las notas de las dos escalas"], a:1, fb:"Am = VI en C (tónica, papel estable) y II en G (subdominante, prepara D7). La reinterpretación es natural — Am como VI en C se desliza hacia Am como II en G, que llama a D7–G." },
{ q:"Al modular de C hacia G, Em es un pivote:", opts:["Imposible — Em no está en G","Posible — Em es III en C y VI en G, dos funciones tónicas","Muy habitual y cadencial","Imposible porque Em es disminuido en G"], a:1, fb:"Em es III en C (tónica) y VI en G (tónica). Es un pivote válido — Em tiene la misma sonoridad en las dos tonalidades (tónica secundaria). Es menos habitual que Am pero funciona." },
{ q:"¿Por qué se evita G como pivote al modular de C hacia G?", opts:["G no está en C","G es la tónica de llegada — usarlo como pivote demasiado pronto revela prematuramente el destino","G es siempre menor","G crea octavas paralelas"], a:1, fb:"G es la tónica de G mayor. Si se escucha demasiado pronto como V de C (su función en C), el oído anticipa la llegada y pierde la sorpresa. Se prefiere un pivote más neutro — Am o Em." },
{ q:"Los acordes comunes entre C mayor y G mayor son:", opts:["C, Dm, Em, F, G, Am","C, Em, G, Am (y Bdim en C = Em en G)","G, D, A, E, B","F, Bb, Eb"], a:1, fb:"C mayor: C Dm Em F G7 Am Bdim. G mayor: G Am Bm C D7 Em F#dim. Acordes comunes: C (I en C / IV en G), Em (III en C / VI en G), Am (VI en C / II en G), G (V en C / I en G)." },
{ q:"Al modular de G hacia D, Bm es un buen pivote porque:", opts:["Bm es mayor en los dos","Bm es III en G (tónica) y VI en D (tónica secundaria) — dos funciones estables","Bm es la dominante de G","Bm no existe en D"], a:1, fb:"Bm es III de G y VI de D — tónica en las dos tonalidades. Es el pivote más natural para la modulación G→D, simétrico a Am para C→G." },
{ q:"La progresión C–Am–D7–G ilustra:", opts:["Una tonicización de Am","Una modulación de C hacia G con Am como pivote","Una cadencia rota","Un bajo de chacona"], a:1, fb:"Am es pivote: VI en C (tónica, la progresión comienza en C) → II en G (subdominante). D7 es la dominante de G. La cadencia D7–G confirma G mayor como nuevo centro tonal." },
{ q:"Al modular de F hacia C, Dm es un pivote porque:", opts:["Dm es mayor en los dos","Dm es VI en F y II en C — funciones tónica y subdominante","Dm es la dominante de F","Dm no existe en C"], a:1, fb:"Dm es VI de F (tónica secundaria) y II de C (subdominante). Al modular F→C, Dm se reinterpreta y prepara G7 (V de C). La cadencia G7–C confirma C." },
{ q:"Para encontrar un acorde pivote, se buscan:", opts:["Un acorde mayor cualquiera","Los acordes comunes a las dos tonalidades — se listan los acordes de cada escala y se encuentran las intersecciones","Un acorde disminuido","Un acorde invertido"], a:1, fb:"Método: (1) listar todos los acordes de la escala de partida, (2) listar todos los acordes de la escala de llegada, (3) encontrar los acordes comunes, (4) elegir el que tenga las funciones más musicales." },
{ q:"El pivote ideal es generalmente:", opts:["La tónica de la escala de partida","Una subdominante o un acorde de función tónica secundaria — ni demasiado marcado ni demasiado inestable","La dominante de la escala de llegada","Un acorde disminuido"], a:1, fb:"Ni la tónica principal (demasiado marcada) ni la dominante (demasiado cadencial) — el pivote ideal es un acorde intermedio: VI o II de partida (= II o VI de llegada). Am para C→G es el ejemplo clásico." },
{ q:"En C mayor, F es un acorde común a:", opts:["C mayor y G mayor","C mayor y F mayor (I de F) y Bb mayor (V de Bb)","C mayor y D menor","C mayor y E menor"], a:1, fb:"F (Fa mayor) es IV de C, I de F y V de Bb. Al modular de C hacia F, F sería la tónica de llegada — evitar como pivote. Hacia Bb, F podría ser pivote (V de Bb = SD de C — papel similar)." },
{ q:"La notación 'pivote' en un análisis armónico se escribe a menudo:", opts:["En rojo","Con un corchete doble — el mismo compás anotado en las dos tonalidades (ej.: [VI en C = II en G])","En 3/4","Con un acorde disminuido"], a:1, fb:"El acorde pivote se anota doblemente: VI en C / II en G (o similar). Esta doble anotación muestra explícitamente la reinterpretación — mismo acorde, dos lecturas funcionales simultáneas." },
{ q:"Al modular de Am hacia C mayor, ¿qué acorde puede servir de pivote?", opts:["G7","Em — III de C y VI de Am (los dos relativos comparten todos sus acordes)","Dm","Bdim"], a:1, fb:"Am y C son relativos — comparten exactamente las mismas 7 notas y los mismos acordes. Cualquier acorde puede ser pivote. Em se usa a menudo: III de C y VI de Am — dos funciones tónicas." },
{ q:"Al modular de C hacia Eb (mediante inferior), los acordes comunes son:", opts:["Numerosos — 6 acordes comunes","Escasos — C y Eb solo comparten Cm (I de Cm y VI de Eb) y Gm","Ninguno — modulación directa obligatoria","F y Bb solamente"], a:1, fb:"C mayor y Eb mayor no comparten muchos acordes diatónicos. Cm puede servir de pivote (minorización de C → I de Cm → VI de Eb). Es una modulación más compleja." },
{ q:"La progresión G–Em–Am–D7–G (en G mayor) muestra:", opts:["Una modulación hacia Am","Una cadencia perfecta en G con Am como acorde de paso","Un retorno a G sin modulación — Am es II de G (subdominante)","Una tonicización de D"], a:1, fb:"No hay modulación aquí — Am es simplemente II de G (subdominante), Em es VI de G (tónica). La progresión es T–T–SD–D–T en G mayor. Am no ha cambiado de tonalidad." },
{ q:"Al modular de D hacia A, F#m es un pivote porque:", opts:["F#m es mayor en D","F#m es III en D (tónica) y VI en A (tónica) — dos funciones estables","F#m es la dominante de D","F#m solo existe en A"], a:1, fb:"F#m es el IIIer grado de D mayor y el VIo grado de A mayor — tónica en las dos tonalidades. Es el pivote natural para D→A, como Bm lo es para G→D y Am para C→G." },
{ q:"¿Qué acorde común a C y F es un buen pivote para modular C→F?", opts:["C (tónica de partida — demasiado marcado)","Am — VI en C y III en F (dos tónicas)","G7 (dominante de C — demasiado cadencial)","Bdim"], a:1, fb:"Am es VI de C (tónica) y III de F (tónica también). Es un pivote neutro y natural. Después de Am en C, se puede reinterpretar Am como III de F y partir hacia C7–F para confirmar F mayor." },
{ q:"Para modular de C hacia Bb, se puede usar Dm como pivote porque:", opts:["Dm es I de Bb","Dm es II en C (subdominante) y III en Bb (tónica) — dos funciones","Dm es la dominante de Bb","Dm no está en Bb"], a:1, fb:"Dm es II de C (SD) y III de Bb (tónica). Reinterpretando Dm como III de Bb, se puede encadenar hacia F7 (V de Bb) y luego Bb. La modulación C→Bb es una modulación hacia la subdominante." },
{ q:"La modulación de C hacia Am (relativo menor):", opts:["Necesita muchos acordes pivotes","Es la más fácil — Am y C comparten todos sus acordes, cualquier acorde puede servir de pivote","Necesita una cadencia directa","Es imposible sin modulación cromática"], a:1, fb:"C y Am son relativos — mismas notas, misma armadura. Cualquier acorde común puede servir de pivote. En la práctica, Em (III/C = VI/Am) o G (V/C = VII/Am) son habituales para esta transición." },
{ q:"La progresión C–F–G7–C–Am–E7–Am muestra:", opts:["Una modulación hacia Am con Am–E7–Am como cadencia perfecta en Am (E7 = V de Am armónico)","Un préstamo de E7","Una tonicización sin modulación","Una cadencia plagal en C"], a:0, fb:"E7 es V de Am armónico (Mi–Sol#–Si–Re). E7–Am es una cadencia perfecta en La menor. Si la progresión permanece en Am después, es una modulación. La progresión C–Am es el pivote (VI de C = I de Am), luego E7–Am confirma Am." },
{ q:"El pivote 'Am = VI en C / II en G' significa que:", opts:["Am cambia de sonoridad según la tonalidad","Am mantiene la misma sonoridad (acorde de La menor) pero su función armónica cambia — tónica en C, subdominante en G","Am se toca de manera diferente en cada tonalidad","Am es un error en una de las dos tonalidades"], a:1, fb:"El acorde Am (La–Do–Mi) permanece idéntico. Solo cambia su interpretación funcional: en C, es una alternativa a la tónica (VI). En G, es un acorde preparatorio hacia D7 (SD). Mismo sonido, dos roles." },
{ q:"El 6/4 de cadencia es:", opts:["Un acorde de sexta añadida","El Ier grado en segunda inversión — la quinta está en el bajo","El Ve grado en primera inversión","Un acorde de sexta napolitana"], a:1, fb:"I6/4 = primer grado en 2ª inversión (la quinta en el bajo). En C: C/G (Do–Mi–Sol con Sol en el bajo). Los intervalos sobre el bajo son una sexta (Mi–Sol) y una cuarta (Sol–Do) — de ahí el nombre 6/4." },
{ q:"¿Por qué el 6/4 de cadencia se coloca justo antes de la dominante?", opts:["Por convención arbitraria","Porque sus notas (cuarta y sexta sobre el bajo) actúan como apoyaturas de la quinta y la tercera de V","Porque es más grave","Porque reemplaza a la subdominante"], a:1, fb:"El 6/4 de cadencia contiene Do (cuarta) y Mi (sexta) sobre Sol. Estas dos notas descienden conjuntamente hacia Si (tercera de G7) y Re (quinta de G7). Es una doble apoyatura de la dominante." },
{ q:"En C mayor, el 6/4 de cadencia se escribe:", opts:["C/E","G/B","C/G","F/C"], a:2, fb:"C/G = Do–Mi–Sol con Sol en el bajo. Es el I en 2ª inversión. Sol es la quinta de C — de ahí el nombre I6/4 (sexta Do–Mi y cuarta Sol–Do sobre el bajo Sol)." },
{ q:"La resolución del 6/4 de cadencia hacia V7 se produce por:", opts:["Un salto de quinta","La cuarta que desciende hacia la tercera de V, y la sexta que desciende hacia la quinta de V","Un movimiento ascendente","Un salto de tercera"], a:1, fb:"Do (cuarta) desciende hacia Si (tercera de G7). Mi (sexta) desciende hacia Re (quinta de G7). Sol (bajo) permanece — es la fundamental de G. Dos descensos conjuntos: Do→Si y Mi→Re. El bajo Sol queda inmóvil." },
{ q:"La secuencia I6/4 → V7 → I es:", opts:["Una cadencia imperfecta","Una cadencia perfecta reforzada — el 6/4 de cadencia prepara el V7 con mayor tensión","Una cadencia rota","Una semicadencia"], a:1, fb:"I6/4 → V7 → I es una cadencia perfecta con preparación. El 6/4 refuerza la tensión antes de V7 — doble apoyatura que amplifica la espera de resolución. Muy usado en los conciertos clásicos." },
{ q:"El V7sus4 es:", opts:["V7 con una séptima suspendida","V7 donde la tercera es temporalmente reemplazada por una cuarta (generalmente la tónica)","V7 en primera inversión","V7 con una 9ª añadida"], a:1, fb:"V7sus4 = acorde de dominante 7 con suspensión de cuarta: la tercera (Si en G7) se reemplaza por la cuarta (Do). En G7sus4: Sol–Do–Re–Fa. La cuarta (Do) se resuelve luego en la tercera (Si): V7sus4 → V7." },
{ q:"En C mayor, G7sus4 contiene las notas:", opts:["Sol–Si–Re–Fa","Sol–Do–Re–Fa","Sol–Si–Mi–Fa","Sol–Do–Mi–Fa"], a:1, fb:"G7sus4 = Sol–Do–Re–Fa. La tercera Si se reemplaza por la cuarta Do. La cuarta Do desciende hacia Si para dar G7 = Sol–Si–Re–Fa. V7sus4 → V7 → I." },
{ q:"La resolución del V7sus4 hacia V7 se produce por:", opts:["Un salto de quinta","La cuarta (Do en G7sus4) que desciende un semitono hacia la tercera (Si en G7)","Un movimiento ascendente","El bajo que asciende"], a:1, fb:"En G7sus4 → G7: Do (cuarta suspendida) desciende un semitono hacia Si (tercera). La suspensión se levanta — la tensión se resuelve hacia la verdadera dominante G7 antes de la resolución final en C." },
{ q:"El V7sus4 crea una tensión más suave que V7 porque:", opts:["Es más grave","La cuarta reemplaza a la tercera — no hay sensible (Si) en el acorde, menos tensión cromática","Es más rápido","Tiene menos notas"], a:1, fb:"G7sus4 no contiene Si (la sensible de C). El acorde es menos tenso que un G7 completo. La suspensión crea una espera elegante — cuando Si llega por fin (V7sus4 → V7), la resolución en C es muy satisfactoria." },
{ q:"La secuencia SD → I6/4 → V7 → I es:", opts:["Una cadencia imperfecta","Una cadencia perfecta con doble preparación — SD prepara 6/4, 6/4 prepara V7","Una semicadencia","Una cadencia rota"], a:1, fb:"SD prepara 6/4 que prepara V7 que resuelve en I. Tres etapas de preparación creciente — cada acorde amplifica la tensión antes de la resolución final. Fórmula clásica para las grandes cadencias." },
{ q:"El 6/4 de cadencia se usa para:", opts:["Comenzar una frase","Confirmar la llegada a una nueva tonalidad antes de la cadencia perfecta","Crear un pedal de dominante","Reemplazar a la subdominante"], a:1, fb:"El 6/4 de cadencia (I6/4 de la nueva tonalidad) se coloca a menudo justo antes de la cadencia perfecta — anuncia firmemente la resolución inminente. Es una 'señal armónica' de la nueva tonalidad." },
{ q:"En un concierto clásico, el 6/4 de cadencia va seguido frecuentemente de:", opts:["La melodía principal","Una cadencia solista — la doble apoyatura resuelve hacia la dominante sobre la que el intérprete improvisa","La recapitulación directa","Un acorde napolitano"], a:1, fb:"La cadencia de concierto usa el 6/4 para marcar el inicio de la cadencia solista. El 6/4 (Sol en el bajo) se mantiene mientras el solista improvisa, luego la orquesta resuelve V7–I al final." },
{ q:"El V7sus4 se usa particularmente en:", opts:["La música barroca únicamente","El jazz, el posromanticismo y la música moderna — por su preparación elegante","La música medieval","Las fugas únicamente"], a:1, fb:"V7sus4 es muy apreciado en el jazz (Herbie Hancock, Bill Evans), el posromanticismo (Wagner, Debussy) y la pop/rock moderna. Ofrece una preparación más colorida y menos convencional que la dominante directa." },
{ q:"El 6/4 de cadencia se llama a veces 'cuarta y sexta' porque:", opts:["Tiene cuatro notas y seis acordes","Los intervalos sobre el bajo son una cuarta y una sexta (desde el bajo hasta las notas del acorde)","Dura cuatro compases","Está en 6/4 de tiempo"], a:1, fb:"Sobre el bajo Sol: Do es una cuarta (Sol→Do = 4 grados) y Mi es una sexta (Sol→Mi = 6 grados). Estos dos intervalos caracterizan el I6/4 = 'acorde de cuarta y sexta' o '6/4 de cadencia'." },
{ q:"¿Cuál es la diferencia entre I6/4 e I6?", opts:["Ninguna diferencia","I6/4 = 2ª inversión (quinta en el bajo), I6 = 1ª inversión (tercera en el bajo)","I6 = 2ª inversión","I6/4 tiene una nota más"], a:1, fb:"I6 = primera inversión: la tercera está en el bajo (C/E en C). I6/4 = segunda inversión: la quinta está en el bajo (C/G en C). La notación cifrada 6/4 y 6 proviene del bajo cifrado barroco." },
{ q:"La secuencia V7sus4 → V7 → I evoca implícitamente:", opts:["Dos tónicas sucesivas","La presencia del Ier y VIIo grado en el movimiento de voces — Do (tónica) en sus4 desciende hacia Si (sensible) que asciende hacia Do","Un préstamo de la dominante","Un acorde napolitano"], a:1, fb:"Do (cuarta suspendida en G7sus4) desciende hacia Si (tercera de G7 = sensible de C). Luego Si asciende hacia Do (resolución final). El Do → Si → Do es un movimiento de suspensión-sensible-resolución implícito en la voz." },
{ q:"¿Por qué el 6/4 de cadencia debe tener el bajo doblado?", opts:["Por estética","Porque el bajo (quinta del acorde) es el sonido más estable del I6/4 — doblarlo refuerza el acorde","Porque la tercera es inestable","Por convención únicamente"], a:1, fb:"En I6/4, el bajo es la quinta del acorde. La regla de duplicación del 6/4 de cadencia: doblar el bajo (= la quinta). La quinta es la nota más neutra — doblarla estabiliza el acorde inestable." },
{ q:"Después de I6/4 → V7, ¿se puede insertar V7sus4 entre los dos?", opts:["No — V7sus4 siempre debe preceder directamente a V7","Sí: I6/4 → V7sus4 → V7 → I es posible y crea una tensión aún más gradual","No — el 6/4 y el sus4 se excluyen","Solo en menor"], a:1, fb:"La secuencia I6/4 → V7sus4 → V7 → I es completamente válida y elaborada. Cada etapa agrega una capa de tensión: 6/4 prepara sus4, sus4 libera la cuarta hacia la tercera, V7 resuelve en I." },
];

const questionsDe: Question[] = [{ q:"Eine Modulation ist:", opts:["Eine Entlehnung eines fremden Akkords","Ein dauerhafter Wechsel der Haupttonart — das tonale Zentrum verschiebt sich","Eine verlängerte Tonikalisierung","Ein Tempowechsel"], a:1, fb:"Die Modulation etabliert dauerhaft eine neue Tonart — sie wird durch eine Ganzschlusskadenz im neuen Zentrum bestätigt. Sie unterscheidet sich von der Entlehnung (momentan) und der Tonikalisierung (kurz)." },
{ q:"Welche Bedingung macht eine Modulation 'real' (dauerhaft)?", opts:["Einen verminderten Akkord verwenden","Die Bestätigung durch eine Ganzschlusskadenz in der neuen Tonart, gefolgt von einem Verbleib","Die Verwendung von Umkehrungen","Das Vorhandensein eines künstlichen Leittons"], a:1, fb:"Eine Modulation ist keine bloße flüchtige Farbe — sie etabliert ein neues tonales Zentrum. Dazu bestätigt eine Ganzschlusskadenz (V–I) in der neuen Tonart die Ankunft. Ohne diesen Verbleib handelt es sich um eine Tonikalisierung." },
{ q:"Was unterscheidet eine Modulation grundlegend von einer Entlehnung?", opts:["Die Dauer — Modulation = dauerhaft, Entlehnung = momentan","Die Tonhöhe der Noten","Die Anzahl der Stimmen","Nur die Vorzeichen"], a:0, fb:"Eine Entlehnung ist eine flüchtige Farbe — man kehrt sofort zur Haupttonart zurück. Die Modulation verschiebt das tonale Zentrum dauerhaft — man verbleibt mehrere Takte in der neuen Tonart." },
{ q:"Die Modulation durch Pivot-Akkord ist die häufigste, weil:", opts:["Sie die schnellste ist","Sie die fließendste ist — der Pivot-Akkord gehört beiden Tonarten an und gewährleistet einen nahtlosen Übergang","Sie die Dominante vermeidet","Sie keine Kadenz erfordert"], a:1, fb:"Der Pivot-Akkord gehört gleichzeitig zur Ausgangs- und zur Zieltonart. Er wird umgedeutet (gleicher Akkord, neue Funktion) — der Übergang ist daher unmerklich, ohne Bruch." },
{ q:"Um die Ankunft in einer neuen Tonart zu bestätigen, verwendet man:", opts:["Einen umgekehrten Akkord","Eine Ganzschlusskadenz (V–I) in der neuen Tonart","Einen neapolitanischen Sextakkord","Eine Tonikalpedal"], a:1, fb:"Die Ganzschlusskadenz in der neuen Tonart — V (in Grundstellung) → I (in Grundstellung) — ist das stärkste Signal, dass sich das tonale Zentrum verschoben hat. Ohne sie bleibt die Modulation mehrdeutig." },
{ q:"Benachbarte Tonarten werden für Modulationen bevorzugt, weil:", opts:["Sie weniger Noten haben","Sie viele Akkorde gemeinsam haben — Pivots sind zahlreich, der Übergang ist sanft","Sie tiefer liegen","Sie weniger Vorzeichen verwenden"], a:1, fb:"Benachbarte Tonarten = 6–7 gemeinsame Noten. Je mehr Noten und Akkorde zwei Tonarten teilen, desto mehr mögliche Pivots gibt es und desto fließender ist die Modulation. Entfernte Tonarten erfordern abruptere Übergänge." },
{ q:"Eine direkte Modulation (ohne Pivot) erzeugt:", opts:["Einen sehr sanften Übergang","Einen brutalen Bruch — theatralischer oder dramatischer Effekt","Eine Halbschlusskadenz","Eine harmonische Verzögerung"], a:1, fb:"Die direkte Modulation (ohne Übergangsakkord) springt abrupt von einer Tonart in die andere. Dieser Effekt kann beabsichtigt sein — um einen dramatischen Wechsel zu markieren — bleibt aber eine stilistische Ausnahme." },
{ q:"Die Tonika der Zieltonart wird als Pivot meist vermieden, weil:", opts:["Sie immer vermindert ist","Sie zu markant ist — die Tonika der neuen Tonart vor der Kadenz zu hören, schwächt die Überraschung der Ankunft ab","Sie nicht zur Ausgangsgamme gehört","Sie Parallelquinten erzeugt"], a:1, fb:"Wenn man die Tonika von G (G-Dur) zu früh als diatonischen Akkord von C (V von C) hört, antizipiert das Ohr die Ankunft. Der ideale Pivot-Akkord ist neutral — er lässt das Ziel nicht zu deutlich erahnen." },
{ q:"Wie lange muss man in der neuen Tonart verbleiben, um eine Modulation zu bestätigen?", opts:["Ein einziger Akkord genügt","Mindestens eine Ganzschlusskadenz — möglichst mehrere Takte","Genau 4 Takte","Eine Oktave lang"], a:1, fb:"Eine Modulation gilt nur dann als bestätigt, wenn man in der neuen Tonart verweilt. Ein einziger Akkord der neuen Tonart ist eine Tonikalisierung. Es bedarf mindestens einer Ganzschlusskadenz, idealerweise mehrerer Takte." },
{ q:"In der Progression C–F–G7–C–Am–D7–G wird die Modulation von C nach G bestätigt durch:", opts:["Am","D7","G — den Schlussakkord","Das Vorhandensein von F# in D7"], a:1, fb:"D7 ist die Dominante von G. D7–G ist die Ganzschlusskadenz in G-Dur. Es ist D7, das bestätigt, dass wir in G sind — er enthält F# (Leitton von G), der nach Sol aufsteigt." },
{ q:"Die Modulation zur Dominante (z. B. C→G) ist in der klassischen Musik die häufigste, weil:", opts:["Sie die dramatischste ist","G die nächste Tonart zu C ist — sie teilen 6 Noten und mehrere gemeinsame Akkorde","C und G die gleichen Vorzeichen haben","Sie den Tritonus vermeidet"], a:1, fb:"C und G unterscheiden sich nur in einer Note (F vs. F#). Es ist die natürlichste Modulation — sehr häufig bei Bach, Haydn, Mozart. Die Modulation zur Dominante wird oft für den B-Teil oder die Durchführung verwendet." },
{ q:"Die Modulation zur parallelen Molltonart (z. B. C→Am) ist charakteristisch für:", opts:["Die Plagalkadenz","Zahlreiche musikalische Formen — das Trio, den kontrastierenden Abschnitt","Die Dominantpedal","Den Quintenzirkel"], a:1, fb:"C-Dur und Am teilen exakt dieselben Noten. Die Modulation zur parallelen Molltonart erzeugt eine Verschiebung hin zu einer dunkleren Farbe, ohne die Noten der Tonleiter zu verändern — sehr natürlich und sehr häufig." },
{ q:"Um von C-Dur nach E♭-Dur (entfernte Tonart) zu modulieren, kann man verwenden:", opts:["Einen direkten Pivot-Akkord (sie teilen wenige Akkorde)","Eine Reihe von graduellen Entlehnungen oder eine dramatische direkte Modulation","Eine Chaconne-Bass","Den vollständigen Quintenzirkel"], a:1, fb:"C und Eb sind weit voneinander entfernt (3 Vorzeichen Unterschied). Ein direkter Pivot ist schwierig — man kann durch Zwischentonarten gehen (progressive Entlehnungen, Chromatik) oder direkt für einen dramatischen Effekt modulieren." },
{ q:"Was ist ein 'typisches Modulationsschema'?", opts:["Ein fester Pivot-Akkord","I–IV–V–I (in der Ausgangstonart), Pivot, V–I (in der Zieltonart) — also T→SD in der Ausgangstonart, Pivot, D→T in der Zieltonart","Zwei aufeinanderfolgende Ganzschlusskadenzen","Ein abrupter Vorzeichenwechsel"], a:1, fb:"Typisches Schema: T–SD (in der Ausgangstonart) → Pivot-Akkord (umgedeutet) → D–T (Ganzschlusskadenz in der neuen Tonart). Der Pivot ist oft eine Subdominante oder ein neutraler Akkord." },
{ q:"Warum wird die Subdominante oft als Pivot-Akkord gewählt?", opts:["Weil sie die tiefste ist","Weil sie auf natürliche Weise die Dominante der neuen Tonart vorbereitet — sie ist funktional 'wartend'","Weil sie immer eine reine Quinte hat","Weil sie immer Dur ist"], a:1, fb:"Die Subdominante bereitet die Dominante vor — das ist ihre Funktion. Als Pivot verwendet, wird sie als SD der neuen Tonart umgedeutet und ruft auf natürliche Weise die Dominante herbei, die die Ankunft bestätigt." },
{ q:"Die Modulation kann vorbereitet werden durch:", opts:["Irgendwelche Akkorde ohne Vorbereitung","Eine progressive Tonikalisierung zur neuen Tonart hin — V/V kann die Modulation nach V vorbereiten","Ausschließlich einen neapolitanischen Akkord","Eine obligatorische Basspedalstimme"], a:1, fb:"Eine Tonikalisierung nach V (z. B. D7 in C, das G vorbereitet) kann eine Modulation werden, wenn man in G verbleibt. V/V bereitet die neue Tonika (G) so natürlich vor, dass der Übergang offensichtlich erscheint." },
{ q:"Wie viele Funktionen hat der Pivot-Akkord in einer Modulation durch Pivot-Akkord?", opts:["Nur eine","Zwei — eine in jeder Tonart (Ausgangs- und Zieltonart)","Drei","Keine — er ist neutral"], a:1, fb:"Der Pivot-Akkord hat zwei gleichzeitige Funktionen: eine in der Ausgangstonart, die andere in der Zieltonart. Diese doppelte Zugehörigkeit ermöglicht den nahtlosen Übergang." },
{ q:"Die Modulation wird in musikalischen Formen oft verwendet, um:", opts:["Das Tempo zu beschleunigen","Kontrast zu erzeugen und dem musikalischen Diskurs Bewegung zu verleihen — Abschnitte A und B, Durchführung","Melodiewiederholungen zu vermeiden","Die Harmonie zu vereinfachen"], a:1, fb:"Die Modulation ist ein mächtiges formales Mittel — sie erzeugt harmonischen Kontrast zwischen den Abschnitten eines Stückes. Die Sonatenform nutzt systematisch die Modulation zur Dominante in der Durchführung." },
{ q:"Ein Pivot-Akkord ist:", opts:["Ein sehr laut gespielter Akkord","Ein Akkord, der gleichzeitig zwei verschiedenen Tonarten angehört — er gewährleistet den Übergang","Ein Dominantseptakkord","Ein Akkord in zweiter Umkehrung"], a:1, fb:"Der Pivot-Akkord ist ein Akkord, der beiden Tonarten angehört — Ausgangs- und Zieltonart. Man spielt ihn einmal mit seiner Funktion in der Ausgangstonart, dann deutet man ihn in der neuen Tonart um. Er ist das Scharnier der Modulation." },
{ q:"Welche Eigenschaft macht einen Akkord zu einem guten Pivot?", opts:["Dur zu sein","Beiden Tonarten anzugehören und in jeder eine natürliche Funktion zu haben — idealerweise nicht-kadenzierend","In Grundstellung zu sein","Keine Vorzeichen zu haben"], a:1, fb:"Ein guter Pivot gehört beiden Tonarten an und hat in jeder eine musikalisch logische Funktion. Er ist idealerweise nicht-kadenzierend (nicht Dominante oder Haupttonika), um die Richtung nicht zu stark vorzuzeichnen." },
{ q:"Bei der Modulation von C nach G ist Am ein ausgezeichneter Pivot, weil:", opts:["Am in beiden Tonarten Dur ist","Am ist VI in C (Tonika) und II in G (Subdominante) — zwei natürliche Funktionen","Am die Dominante beider Tonarten ist","Am alle Noten beider Tonleitern enthält"], a:1, fb:"Am = VI in C (Tonika, stabile Rolle) und II in G (Subdominante, bereitet D7 vor). Die Umdeutung ist natürlich — Am als VI in C gleitet zu Am als II in G, das D7–G herbeiruft." },
{ q:"Bei der Modulation von C nach G ist Em ein Pivot:", opts:["Unmöglich — Em ist nicht in G","Möglich — Em ist III in C und VI in G, zwei Tonika-Funktionen","Sehr häufig und kadenzierend","Unmöglich, da Em in G vermindert ist"], a:1, fb:"Em ist III in C (Tonika) und VI in G (Tonika). Es ist ein gültiger Pivot — Em hat in beiden Tonarten denselben Klang (Tonika-Nebenakkord). Er ist weniger gebräuchlich als Am, funktioniert aber." },
{ q:"Warum vermeidet man G als Pivot bei der Modulation von C nach G?", opts:["G ist nicht in C","G ist die Zieltonika — ihn zu früh als Pivot zu verwenden, lässt das Ziel vorzeitig erkennen","G ist immer Moll","G erzeugt Parallelquinten"], a:1, fb:"G ist die Tonika von G-Dur. Wenn man ihn zu früh als V von C (seine Funktion in C) hört, antizipiert das Ohr die Ankunft und verliert die Überraschung. Man bevorzugt einen neutraleren Pivot — Am oder Em." },
{ q:"Die gemeinsamen Akkorde zwischen C-Dur und G-Dur sind:", opts:["C, Dm, Em, F, G, Am","C, Em, G, Am (und Bdim in C = Em in G)","G, D, A, E, B","F, Bb, Eb"], a:1, fb:"C-Dur: C Dm Em F G7 Am Bdim. G-Dur: G Am Bm C D7 Em F#dim. Gemeinsame Akkorde: C (I in C / IV in G), Em (III in C / VI in G), Am (VI in C / II in G), G (V in C / I in G)." },
{ q:"Bei der Modulation von G nach D ist Bm ein guter Pivot, weil:", opts:["Bm in beiden Tonarten Dur ist","Bm ist III in G (Tonika) und VI in D (Tonika-Nebenakkord) — zwei stabile Funktionen","Bm die Dominante von G ist","Bm in D nicht existiert"], a:1, fb:"Bm ist III von G und VI von D — Tonika in beiden Tonarten. Es ist der natürlichste Pivot für die Modulation G→D, symmetrisch zu Am für C→G." },
{ q:"Die Progression C–Am–D7–G illustriert:", opts:["Eine Tonikalisierung von Am","Eine Modulation von C nach G mit Am als Pivot","Eine Trugschluss-Kadenz","Einen Chaconne-Bass"], a:1, fb:"Am ist Pivot: VI in C (Tonika, die Progression beginnt in C) → II in G (Subdominante). D7 ist die Dominante von G. Die Kadenz D7–G bestätigt G-Dur als neues tonales Zentrum." },
{ q:"Bei der Modulation von F nach C ist Dm ein Pivot, weil:", opts:["Dm in beiden Tonarten Dur ist","Dm ist VI in F und II in C — Tonika- und Subdominante-Funktionen","Dm die Dominante von F ist","Dm in C nicht existiert"], a:1, fb:"Dm ist VI von F (Tonika-Nebenakkord) und II von C (Subdominante). Bei der Modulation F→C wird Dm umgedeutet und bereitet G7 (V von C) vor. Die Kadenz G7–C bestätigt C." },
{ q:"Um einen Pivot-Akkord zu finden, sucht man:", opts:["Irgendwelche Dur-Akkorde","Die gemeinsamen Akkorde beider Tonarten — man listet die Akkorde jeder Tonleiter auf und findet die Schnittmengen","Einen verminderten Akkord","Einen umgekehrten Akkord"], a:1, fb:"Methode: (1) alle Akkorde der Ausgangsgamme auflisten, (2) alle Akkorde der Zielgamme auflisten, (3) die gemeinsamen Akkorde finden, (4) denjenigen mit den musikalischsten Funktionen wählen." },
{ q:"Der ideale Pivot ist in der Regel:", opts:["Die Tonika der Ausgangsgamme","Eine Subdominante oder ein Tonika-Nebenakkord — weder zu markant noch zu instabil","Die Dominante der Zielgamme","Ein verminderter Akkord"], a:1, fb:"Weder die Haupttonika (zu markant) noch die Dominante (zu kadenzierend) — der ideale Pivot ist ein mittlerer Akkord: VI oder II der Ausgangstonart (= II oder VI der Zieltonart). Am für C→G ist das klassische Beispiel." },
{ q:"In C-Dur ist F ein gemeinsamer Akkord mit:", opts:["C-Dur und G-Dur","C-Dur und F-Dur (I von F) und Bb-Dur (V von Bb)","C-Dur und D-Moll","C-Dur und E-Moll"], a:1, fb:"F (Fa-Dur) ist IV von C, I von F und V von Bb. Bei der Modulation von C nach F wäre F die Zieltonika — als Pivot zu vermeiden. Nach Bb könnte F ein Pivot sein (V von Bb = ähnliche Rolle wie SD von C)." },
{ q:"Die Notation 'Pivot' in einer harmonischen Analyse wird oft notiert:", opts:["In Rot","Mit einer doppelten Klammer — derselbe Takt in beiden Tonarten kommentiert (z. B. [VI in C = II in G])","Im 3/4-Takt","Mit einem verminderten Akkord"], a:1, fb:"Der Pivot-Akkord wird doppelt kommentiert: VI in C / II in G (oder ähnlich). Diese doppelte Notation zeigt explizit die Umdeutung — gleicher Akkord, zwei simultane funktionale Lesarten." },
{ q:"Bei der Modulation von Am nach C-Dur kann welcher Akkord als Pivot dienen?", opts:["G7","Em — III von C und VI von Am (die beiden Parallelen teilen alle ihre Akkorde)","Dm","Bdim"], a:1, fb:"Am und C sind Paralleltonarten — sie teilen exakt dieselben 7 Noten und dieselben Akkorde. Jeder Akkord kann als Pivot dienen. Em wird oft verwendet: III von C und VI von Am — zwei Tonika-Funktionen." },
{ q:"Bei der Modulation von C nach Eb (untere Mediante) sind die gemeinsamen Akkorde:", opts:["Zahlreich — 6 gemeinsame Akkorde","Selten — C und Eb teilen nur Cm (I von Cm und VI von Eb) und Gm","Keine — direkte Modulation obligatorisch","Nur F und Bb"], a:1, fb:"C-Dur und Eb-Dur teilen nicht viele diatonische Akkorde. Cm kann als Pivot dienen (Mollisierung von C → I von Cm → VI von Eb). Es handelt sich um eine komplexere Modulation." },
{ q:"Die Progression G–Em–Am–D7–G (in G-Dur) zeigt:", opts:["Eine Modulation nach Am","Eine Ganzschlusskadenz in G mit Am als Durchgangsakkord","Eine Rückkehr nach G ohne Modulation — Am ist II von G (Subdominante)","Eine Tonikalisierung von D"], a:1, fb:"Keine Modulation hier — Am ist einfach II von G (Subdominante), Em ist VI von G (Tonika). Die Progression ist T–T–SD–D–T in G-Dur. Am hat die Tonart nicht gewechselt." },
{ q:"Bei der Modulation von D nach A ist F#m ein Pivot, weil:", opts:["F#m in D Dur ist","F#m ist III in D (Tonika) und VI in A (Tonika) — zwei stabile Funktionen","F#m die Dominante von D ist","F#m nur in A existiert"], a:1, fb:"F#m ist der III. Grad von D-Dur und der VI. Grad von A-Dur — Tonika in beiden Tonarten. Es ist der natürliche Pivot für D→A, wie Bm es für G→D und Am für C→G ist." },
{ q:"Welcher gemeinsame Akkord von C und F ist ein guter Pivot für die Modulation C→F?", opts:["C (Ausgangstonika — zu markant)","Am — VI in C und III in F (zwei Tonika-Funktionen)","G7 (Dominante von C — zu kadenzierend)","Bdim"], a:1, fb:"Am ist VI von C (Tonika) und III von F (ebenfalls Tonika). Es ist ein neutraler und natürlicher Pivot. Nach Am in C kann man Am als III von F umdeuten und zu C7–F gehen, um F-Dur zu bestätigen." },
{ q:"Um von C nach Bb zu modulieren, kann man Dm als Pivot verwenden, weil:", opts:["Dm I von Bb ist","Dm ist II in C (Subdominante) und III in Bb (Tonika) — zwei Funktionen","Dm die Dominante von Bb ist","Dm nicht in Bb ist"], a:1, fb:"Dm ist II von C (SD) und III von Bb (Tonika). Indem man Dm als III von Bb umdeutet, kann man zu F7 (V von Bb) und dann Bb gehen. Die Modulation C→Bb ist eine Modulation zur Subdominante." },
{ q:"Die Modulation von C nach Am (parallele Molltonart):", opts:["Erfordert viele Pivot-Akkorde","Ist die einfachste — Am und C teilen alle ihre Akkorde, jeder Akkord kann als Pivot dienen","Erfordert eine direkte Kadenz","Ist ohne chromatische Modulation unmöglich"], a:1, fb:"C und Am sind Paralleltonarten — gleiche Noten, gleiche Vorzeichen. Jeder gemeinsame Akkord kann als Pivot dienen. In der Praxis sind Em (III/C = VI/Am) oder G (V/C = VII/Am) für diesen Übergang gebräuchlich." },
{ q:"Die Progression C–F–G7–C–Am–E7–Am zeigt:", opts:["Eine Modulation nach Am mit Am–E7–Am als Ganzschlusskadenz in Am (E7 = V von harmonischem Am)","Eine Entlehnung von E7","Eine Tonikalisierung ohne Modulation","Eine Plagalkadenz in C"], a:0, fb:"E7–Am ist die Ganzschlusskadenz von A-Moll (E7 = V von harmonischem Am, enthält G#). Wenn man nach Am verbleibt, ist es eine Modulation. Die Progression C–Am ist der Pivot (VI von C = I von Am), dann bestätigt E7–Am." },
{ q:"Der Pivot 'Am = VI in C / II in G' bedeutet, dass:", opts:["Am seinen Klang je nach Tonart ändert","Am seinen Klang (Akkord von A-Moll) beibehält, aber seine harmonische Funktion wechselt — Tonika in C, Subdominante in G","Am in jeder Tonart anders gespielt wird","Am in einer der beiden Tonarten ein Fehler ist"], a:1, fb:"Der Akkord Am (La–Do–Mi) bleibt identisch. Nur seine funktionale Deutung ändert sich: in C ist er eine Tonika-Alternative (VI). In G ist er ein vorbereitender Akkord zu D7 (SD). Gleicher Klang, zwei Rollen." },
{ q:"Der Quartsextakkord der Kadenz ist:", opts:["Ein Sextakkord mit hinzugefügter Sexte","Der I. Grad in zweiter Umkehrung — die Quinte liegt im Bass","Der V. Grad in erster Umkehrung","Ein neapolitanischer Sextakkord"], a:1, fb:"I6/4 = erster Grad in 2. Umkehrung (die Quinte im Bass). In C: C/G (Do–Mi–Sol mit Sol im Bass). Die Intervalle über dem Bass sind eine Sexte (Mi–Sol) und eine Quarte (Sol–Do) — daher der Name 6/4." },
{ q:"Warum wird der Quartsextakkord der Kadenz direkt vor der Dominante platziert?", opts:["Aus willkürlicher Konvention","Weil seine Noten (Quarte und Sexte über dem Bass) als Vorhalte zur Quinte und Terz von V wirken","Weil er tiefer liegt","Weil er die Subdominante ersetzt"], a:1, fb:"Der Quartsextakkord der Kadenz enthält Do (Quarte) und Mi (Sexte) über Sol. Diese beiden Noten steigen stufenweise ab zu Si (Terz von G7) und Ré (Quinte von G7). Es handelt sich um einen Doppelvorhalt zur Dominante." },
{ q:"In C-Dur wird der Quartsextakkord der Kadenz notiert als:", opts:["C/E","G/B","C/G","F/C"], a:2, fb:"C/G = Do–Mi–Sol mit Sol im Bass. Das ist I in 2. Umkehrung. Sol ist die Quinte von C — daher der Name I6/4 (Sexte Do–Mi und Quarte Sol–Do über dem Bass Sol)." },
{ q:"Die Auflösung des Quartsextakkords der Kadenz zu V7 erfolgt durch:", opts:["Einen Quintsprung","Die Quarte, die zur Terz von V absteigt, und die Sexte, die zur Quinte von V absteigt","Eine aufsteigende Bewegung","Einen Terzsprung"], a:1, fb:"Do (Quarte) steigt ab zu Si (Terz von G7). Mi (Sexte) steigt ab zu Ré (Quinte von G7). Sol (Bass) bleibt liegen — das ist die Grundnote von G. Zwei stufenweise Absteigebewegungen: Do→Si und Mi→Ré. Der Bass Sol bleibt unbeweglich." },
{ q:"Die Sequenz I6/4 → V7 → I ist:", opts:["Eine Halbschlusskadenz","Eine verstärkte Ganzschlusskadenz — der 6/4 bereitet V7 mit mehr Spannung vor","Eine Trugschlusskadenz","Eine Plagalkadenz"], a:1, fb:"I6/4 → V7 → I ist eine Ganzschlusskadenz mit Vorbereitung. Der 6/4 verstärkt die Spannung vor V7 — Doppelvorhalt, der die Auflösungserwartung verstärkt. Sehr häufig in klassischen Konzerten verwendet." },
{ q:"V7sus4 ist:", opts:["V7 mit einer hängenden Septime","V7, bei dem die Terz vorübergehend durch eine Quarte ersetzt wird (oft die Tonika)","V7 in erster Umkehrung","V7 mit hinzugefügter None"], a:1, fb:"V7sus4 = Dominantseptakkord mit Quartvorhalt: die Terz (Si in G7) wird durch die Quarte (Do) ersetzt. In G7sus4: Sol–Do–Ré–Fa. Die Quarte (Do) löst sich dann zur Terz (Si) auf: V7sus4 → V7." },
{ q:"In C-Dur enthält G7sus4 die Noten:", opts:["Sol–Si–Ré–Fa","Sol–Do–Ré–Fa","Sol–Si–Mi–Fa","Sol–Do–Mi–Fa"], a:1, fb:"G7sus4 = Sol–Do–Ré–Fa. Die Terz Si wird durch die Quarte Do ersetzt. Die Quarte Do steigt ab zu Si, um G7 = Sol–Si–Ré–Fa zu ergeben. V7sus4 → V7 → I." },
{ q:"Die Auflösung von V7sus4 zu V7 erfolgt durch:", opts:["Einen Quintsprung","Die Quarte (Do in G7sus4), die einen Halbton zur Terz (Si in G7) absteigt","Eine aufsteigende Bewegung","Den aufsteigenden Bass"], a:1, fb:"In G7sus4 → G7: Do (Quartvorhalt) steigt einen Halbton ab zu Si (Terz). Der Vorhalt löst sich auf — die Spannung löst sich zur echten Dominante G7, bevor die endgültige Auflösung auf C erfolgt." },
{ q:"V7sus4 erzeugt eine weichere Spannung als V7, weil:", opts:["Er tiefer liegt","Die Quarte die Terz ersetzt — kein Leitton (Si) im Akkord, weniger chromatische Spannung","Er schneller ist","Er weniger Noten hat"], a:1, fb:"G7sus4 enthält kein Si (den Leitton von C). Der Akkord ist weniger gespannt als ein vollständiges G7. Der Vorhalt erzeugt eine elegante Erwartung — wenn Si endlich erscheint (V7sus4 → V7), ist die Auflösung auf C sehr befriedigend." },
{ q:"Die Sequenz SD → I6/4 → V7 → I ist:", opts:["Eine Halbschlusskadenz","Eine Ganzschlusskadenz mit doppelter Vorbereitung — SD bereitet 6/4 vor, 6/4 bereitet V7 vor","Eine Plagalkadenz","Eine Trugschlusskadenz"], a:1, fb:"SD bereitet 6/4 vor, das V7 vorbereitet, das auf I auflöst. Drei Stufen zunehmender Vorbereitung — jeder Akkord verstärkt die Spannung vor der Schlussauflösung. Klassische Formel für große Kadenzen." },
];

const questionsIt: Question[] = [{ q:"Una modulazione è:", opts:["Un prestito di accordo estraneo","Un cambiamento duraturo di tonalità principale — il centro tonale si sposta","Una tonicizzazione prolungata","Un cambiamento di tempo"], a:1, fb:"La modulazione installa durevolmente una nuova tonalità — è confermata da una cadenza perfetta nel nuovo centro. Si distingue dal prestito (momentaneo) e dalla tonicizzazione (breve)." },
{ q:"Quale condizione rende una modulazione 'reale' (duratura)?", opts:["Usare un accordo diminuito","La conferma tramite una cadenza perfetta nella nuova tonalità, seguita da una permanenza","L'uso di accordi rivolti","La presenza di una sensibile artificiale"], a:1, fb:"Una modulazione non è un semplice colore passeggero — installa un nuovo centro tonale. Per questo, una cadenza perfetta (V–I) nella nuova tonalità ne conferma l'arrivo. Senza questa permanenza, è una tonicizzazione." },
{ q:"Cosa distingue fondamentalmente una modulazione da un prestito?", opts:["La durata — modulazione = duratura, prestito = momentaneo","L'altezza delle note","Il numero di voci","L'armatura soltanto"], a:0, fb:"Un prestito è un colore passeggero — si torna immediatamente alla tonalità principale. La modulazione sposta durevolmente il centro tonale — si rimane nella nuova tonalità per diverse misure." },
{ q:"La modulazione per accordo pivot è la più frequente perché:", opts:["È la più rapida","È la più fluida — l'accordo pivot appartiene a entrambe le tonalità, assicurando una transizione senza rottura","Evita la dominante","Non richiede una cadenza"], a:1, fb:"L'accordo pivot appartiene simultaneamente alla tonalità di partenza e a quella di arrivo. Lo si reinterpreta (stesso accordo, nuova funzione) — la transizione è quindi impercettibile, senza rottura." },
{ q:"Per confermare l'arrivo in una nuova tonalità si usa:", opts:["Un accordo rivolto","Una cadenza perfetta (V–I) nella nuova tonalità","Un accordo di sesta napoletana","Una pedale di tonica"], a:1, fb:"La cadenza perfetta nella nuova tonalità — V (allo stato fondamentale) → I (allo stato fondamentale) — è il segnale più forte che il centro tonale è cambiato. Senza di essa, la modulazione rimane ambigua." },
{ q:"Le tonalità vicine sono privilegiate per le modulazioni perché:", opts:["Hanno meno note","Condividono molti accordi — i pivot abbondano, la transizione è morbida","Sono più gravi","Usano meno alterazioni"], a:1, fb:"Tonalità vicine = 6-7 note comuni. Più le due tonalità condividono note e accordi, più ci sono pivot possibili e più la modulazione è fluida. Le tonalità lontane richiedono transizioni più brusche." },
{ q:"Una modulazione diretta (senza pivot) crea:", opts:["Una transizione molto morbida","Una rottura brusca — effetto teatrale o drammatico","Una cadenza imperfetta","Un ritardo armonico"], a:1, fb:"La modulazione diretta (senza accordo di transizione) salta bruscamente da una tonalità all'altra. Questo effetto può essere voluto — per segnare un cambiamento drammatico — ma rimane un'eccezione stilistica." },
{ q:"La tonica della tonalità di arrivo è generalmente evitata come pivot perché:", opts:["È sempre diminuita","È troppo marcata — sentire la tonica della nuova tonalità prima della cadenza indebolisce la sorpresa dell'arrivo","Non appartiene alla scala di partenza","Crea ottave parallele"], a:1, fb:"Se si sente la tonica di G (Sol maggiore) troppo presto come accordo diatonico di C (V di C), l'orecchio anticipa l'arrivo. L'accordo pivot ideale è neutro — non prefigura troppo nettamente la destinazione." },
{ q:"Quanto tempo occorre rimanere nella nuova tonalità per validare una modulazione?", opts:["Basta un solo accordo","Almeno una cadenza perfetta — preferibilmente diverse misure","Esattamente 4 misure","Un'ottava di durata"], a:1, fb:"Una modulazione è validata solo se ci si trattiene nella nuova tonalità. Un solo accordo della nuova tonalità è una tonicizzazione. Occorre come minimo una cadenza perfetta, idealmente diverse misure." },
{ q:"Nella progressione C–F–G7–C–Am–D7–G, la modulazione da C verso G è confermata da:", opts:["Am","D7","G — l'accordo finale","La presenza di F# in D7"], a:1, fb:"D7 è la dominante di G. D7–G è la cadenza perfetta in Sol maggiore. È D7 che conferma di essere in G — contiene F# (sensibile di G) che sale verso Sol." },
{ q:"La modulazione verso la dominante (es.: C→G) è la più frequente nella musica classica perché:", opts:["È la più drammatica","G è la tonalità più vicina a C — condividono 6 note e diversi accordi comuni","C e G hanno la stessa armatura","Evita il tritono"], a:1, fb:"C e G differiscono di una sola nota (F vs F#). È la modulazione più naturale — molto frequente in Bach, Haydn, Mozart. La modulazione verso la dominante è spesso usata per la sezione B o lo sviluppo." },
{ q:"La modulazione verso il relativo minore (es.: C→Am) è caratteristica di:", opts:["La cadenza plagale","Numerose forme musicali — il trio, la sezione contrastante","La pedale di dominante","Il ciclo delle quinte"], a:1, fb:"C maggiore e Am condividono esattamente le stesse note. La modulazione verso il relativo minore crea uno scivolamento verso un colore più scuro senza cambiare le note della scala — molto naturale e molto frequente." },
{ q:"Per modulare da C maggiore verso E♭ maggiore (tonalità lontana), si può usare:", opts:["Un accordo pivot diretto (condividono pochi accordi)","Una serie di prestiti graduali o una modulazione diretta drammatica","Una bassa di ciaccona","Il ciclo delle quinte completo"], a:1, fb:"C ed Eb sono lontane (3 bemolle di differenza). Un pivot diretto è difficile — si può passare per tonalità intermedie (prestiti progressivi, cromatismo) o modulare direttamente per un effetto drammatico." },
{ q:"Che cos'è uno 'schema di modulazione tipo'?", opts:["Un accordo pivot fisso","I–IV–V–I (in partenza), pivot, V–I (in arrivo) — ovvero T→SD nella partenza, pivot, D→T nell'arrivo","Due cadenze perfette consecutive","Un cambiamento brusco di armatura"], a:1, fb:"Schema tipo: T–SD (nella tonalità di partenza) → accordo pivot (reinterpretato) → D–T (cadenza perfetta nella nuova tonalità). Il pivot è spesso una sottodominante o un accordo neutro." },
{ q:"Perché la sottodominante è spesso scelta come accordo pivot?", opts:["Perché è la più grave","Perché prepara naturalmente la dominante della nuova tonalità — è funzionalmente 'in attesa'","Perché ha sempre una quinta giusta","Perché è sempre maggiore"], a:1, fb:"La sottodominante prepara la dominante — è la sua funzione. Usata come pivot, si reinterpreta come SD della nuova tonalità e chiama naturalmente la dominante che conferma l'arrivo." },
{ q:"La modulazione può essere preparata da:", opts:["Qualsiasi accordo senza preparazione","Una tonicizzazione progressiva verso la nuova tonalità — V/V può preparare la modulazione verso V","Un accordo napoletano soltanto","Una pedale di basso obbligatoria"], a:1, fb:"Una tonicizzazione verso V (es.: D7 in C che prepara G) può diventare una modulazione se si rimane in G. Il V/V prepara così naturalmente la nuova tonica (G) che la transizione sembra evidente." },
{ q:"In una modulazione per accordo pivot, quante funzioni ha l'accordo pivot?", opts:["Una sola","Due — una in ciascuna tonalità (partenza e arrivo)","Tre","Nessuna — è neutro"], a:1, fb:"L'accordo pivot ha due funzioni simultanee: una nella tonalità di partenza, l'altra in quella di arrivo. È questa doppia appartenenza che permette la transizione senza rottura." },
{ q:"La modulazione è spesso usata nelle forme musicali per:", opts:["Accelerare il tempo","Creare un contrasto e dare movimento al discorso musicale — sezioni A e B, sviluppo","Evitare le ripetizioni melodiche","Semplificare l'armonia"], a:1, fb:"La modulazione è uno strumento formale potente — crea un contrasto armonico tra le sezioni di un brano. La forma sonata sfrutta sistematicamente la modulazione verso la dominante nello sviluppo." },
{ q:"Un accordo pivot è:", opts:["Un accordo suonato molto forte","Un accordo appartenente simultaneamente a due tonalità diverse — assicura la transizione","Un accordo di dominante secondaria","Un accordo in secondo rivolto"], a:1, fb:"L'accordo pivot è un accordo che appartiene a entrambe le tonalità — partenza e arrivo. Lo si suona una volta con la sua funzione di partenza, poi lo si reinterpreta nella nuova tonalità. È il cardine della modulazione." },
{ q:"Quale proprietà fa di un accordo un buon pivot?", opts:["Essere maggiore","Appartenere a entrambe le tonalità e avere una funzione naturale in ciascuna — idealmente non cadenziale","Essere allo stato fondamentale","Non avere alcuna alterazione"], a:1, fb:"Un buon pivot appartiene a entrambe le tonalità e ha una funzione musicalmente logica in ciascuna. È idealmente non cadenziale (non la dominante né la tonica principale) per non marcare troppo la direzione." },
{ q:"Modulando da C verso G, Am è un ottimo pivot perché:", opts:["Am è maggiore in entrambe le tonalità","Am è VI in C (tonica secondaria) e II in G (sottodominante) — due funzioni naturali","Am è la dominante di entrambe","Am contiene tutte le note di entrambe le scale"], a:1, fb:"Am = VI in C (tonica, ruolo stabile) e II in G (sottodominante, prepara D7). La reinterpretazione è naturale — Am come VI in C scivola verso Am come II in G, che chiama D7–G." },
{ q:"Modulando da C verso G, Em è un pivot:", opts:["Impossibile — Em non è in G","Possibile — Em è III in C e VI in G, due funzioni toniche","Molto comune e cadenziale","Impossibile perché Em è diminuito in G"], a:1, fb:"Em è III in C (tonica) e VI in G (tonica). È un pivot valido — Em ha la stessa sonorità in entrambe le tonalità (tonica secondaria). È meno comune di Am ma funziona." },
{ q:"Perché si evita G come pivot modulando da C verso G?", opts:["G non è in C","G è la tonica di arrivo — usarlo come pivot troppo presto rivela prematuramente la destinazione","G è sempre minore","G crea ottave parallele"], a:1, fb:"G è la tonica di Sol maggiore. Se la si sente troppo presto come V di C (sua funzione in C), l'orecchio anticipa l'arrivo e perde la sorpresa. Si preferisce un pivot più neutro — Am o Em." },
{ q:"Gli accordi comuni tra C maggiore e G maggiore sono:", opts:["C, Dm, Em, F, G, Am","C, Em, G, Am (e Bdim in C = Em in G)","G, D, A, E, B","F, Bb, Eb"], a:1, fb:"C maggiore: C Dm Em F G7 Am Bdim. G maggiore: G Am Bm C D7 Em F#dim. Accordi comuni: C (I in C / IV in G), Em (III in C / VI in G), Am (VI in C / II in G), G (V in C / I in G)." },
{ q:"Modulando da G verso D, Bm è un buon pivot perché:", opts:["Bm è maggiore in entrambe","Bm è III in G (tonica) e VI in D (tonica secondaria) — due funzioni stabili","Bm è la dominante di G","Bm non esiste in D"], a:1, fb:"Bm è III di G e VI di D — tonica in entrambe le tonalità. È il pivot più naturale per la modulazione G→D, simmetrico ad Am per C→G." },
{ q:"La progressione C–Am–D7–G illustra:", opts:["Una tonicizzazione di Am","Una modulazione da C verso G con Am come pivot","Una cadenza d'inganno","Una bassa di ciaccona"], a:1, fb:"Am è pivot: VI in C (tonica, la progressione inizia in C) → II in G (sottodominante). D7 è la dominante di G. La cadenza D7–G conferma Sol maggiore come nuovo centro tonale." },
{ q:"Modulando da F verso C, Dm è un pivot perché:", opts:["Dm è maggiore in entrambe","Dm è VI in F e II in C — funzioni di tonica e sottodominante","Dm è la dominante di F","Dm non esiste in C"], a:1, fb:"Dm è VI di F (tonica secondaria) e II di C (sottodominante). Modulando F→C, Dm si reinterpreta e prepara G7 (V di C). La cadenza G7–C conferma C." },
{ q:"Per trovare un accordo pivot, si cercano:", opts:["Un accordo maggiore qualsiasi","Gli accordi comuni alle due tonalità — si elencano gli accordi di ciascuna scala e si trovano le intersezioni","Un accordo diminuito","Un accordo rivolto"], a:1, fb:"Metodo: (1) elencare tutti gli accordi della scala di partenza, (2) elencare tutti gli accordi della scala di arrivo, (3) trovare gli accordi comuni, (4) scegliere quello con le funzioni più musicali." },
{ q:"Il pivot ideale è generalmente:", opts:["La tonica della scala di partenza","Una sottodominante o un accordo di funzione tonica secondaria — né troppo marcato né troppo instabile","La dominante della scala di arrivo","Un accordo diminuito"], a:1, fb:"Né la tonica principale (troppo marcata) né la dominante (troppo cadenziale) — il pivot ideale è un accordo intermedio: VI o II di partenza (= II o VI di arrivo). Am per C→G è l'esempio classico." },
{ q:"In C maggiore, F è un accordo comune a:", opts:["C maggiore e G maggiore","C maggiore e F maggiore (I di F) e Bb maggiore (V di Bb)","C maggiore e D minore","C maggiore e E minore"], a:1, fb:"F (Fa maggiore) è IV di C, I di F e V di Bb. Modulando da C verso F, F sarebbe la tonica di arrivo — da evitare come pivot. Verso Bb, F potrebbe essere un pivot (V di Bb = SD di C — ruolo simile)." },
{ q:"La notazione 'pivot' in un'analisi armonica si scrive spesso:", opts:["In rosso","Con una doppia parentesi — la stessa misura annotata nelle due tonalità (es.: [VI in C = II in G])","In 3/4","Con un accordo diminuito"], a:1, fb:"L'accordo pivot è annotato doppiamente: VI in C / II in G (o simile). Questa doppia annotazione mostra esplicitamente la reinterpretazione — stesso accordo, due letture funzionali simultanee." },
{ q:"Modulando da Am verso C maggiore, quale accordo può servire da pivot?", opts:["G7","Em — III di C e VI di Am (i due relativi condividono tutti i loro accordi)","Dm","Bdim"], a:1, fb:"Am e C sono relativi — condividono esattamente le stesse 7 note e gli stessi accordi. Qualsiasi accordo può essere pivot. Em è spesso usato: III di C e VI di Am — due funzioni toniche." },
{ q:"Modulando da C verso Eb (mediante inferiore), gli accordi comuni sono:", opts:["Numerosi — 6 accordi comuni","Rari — C ed Eb condividono solo Cm (I di Cm e VI di Eb) e Gm","Nessuno — modulazione diretta obbligatoria","F e Bb soltanto"], a:1, fb:"C maggiore ed Eb maggiore non condividono molti accordi diatonici. Cm può servire da pivot (minorizzazione di C → I di Cm → VI di Eb). È una modulazione più complessa." },
{ q:"La progressione G–Em–Am–D7–G (in Sol maggiore) mostra:", opts:["Una modulazione verso Am","Una cadenza perfetta in G con Am come accordo di passaggio","Un ritorno a G senza modulazione — Am è II di G (sottodominante)","Una tonicizzazione di D"], a:1, fb:"Nessuna modulazione qui — Am è semplicemente II di G (sottodominante), Em è VI di G (tonica). La progressione è T–T–SD–D–T in Sol maggiore. Am non ha cambiato tonalità." },
{ q:"Modulando da D verso A, F#m è un pivot perché:", opts:["F#m è maggiore in D","F#m è III in D (tonica) e VI in A (tonica) — due funzioni stabili","F#m è la dominante di D","F#m esiste solo in A"], a:1, fb:"F#m è il III grado di D maggiore e il VI grado di A maggiore — tonica in entrambe le tonalità. È il pivot naturale per D→A, come Bm lo è per G→D e Am per C→G." },
{ q:"Quale accordo comune a C e F è un buon pivot per modulare C→F?", opts:["C (tonica di partenza — troppo marcata)","Am — VI in C e III in F (due toniche)","G7 (dominante di C — troppo cadenziale)","Bdim"], a:1, fb:"Am è VI di C (tonica) e III di F (tonica). È un pivot neutro e naturale. Dopo Am in C, si può reinterpretare Am come III di F e proseguire verso C7–F per confermare Fa maggiore." },
{ q:"Per modulare da C verso Bb, si può usare Dm come pivot perché:", opts:["Dm è I di Bb","Dm è II in C (sottodominante) e III in Bb (tonica) — due funzioni","Dm è la dominante di Bb","Dm non è in Bb"], a:1, fb:"Dm è II di C (SD) e III di Bb (tonica). Reinterpretando Dm come III di Bb, si può proseguire verso F7 (V di Bb) poi Bb. La modulazione C→Bb è una modulazione verso la sottodominante." },
{ q:"La modulazione da C verso Am (relativo minore):", opts:["Richiede molti accordi pivot","È la più semplice — Am e C condividono tutti i loro accordi, qualsiasi accordo può servire da pivot","Richiede una cadenza diretta","È impossibile senza modulazione cromatica"], a:1, fb:"C e Am sono relativi — stesse note, stessa armatura. Qualsiasi accordo comune può servire da pivot. In pratica, Em (III/C = VI/Am) o G (V/C = VII/Am) sono comuni per questa transizione." },
{ q:"La progressione C–F–G7–C–Am–E7–Am mostra:", opts:["Una modulazione verso Am con Am–E7–Am come cadenza perfetta in Am (E7 = V di Am armonico)","Un prestito di E7","Una tonicizzazione senza modulazione","Una cadenza plagale in C"], a:0, fb:"E7 è V di Am armonico (Mi–Sol#–Si–Re). E7–Am è una cadenza perfetta in La minore. Se si rimane in Am dopo, è una modulazione. La progressione C–Am è il pivot (VI di C = I di Am), poi E7–Am conferma Am." },
{ q:"Il pivot 'Am = VI in C / II in G' significa che:", opts:["Am cambia sonorità secondo la tonalità","Am mantiene la stessa sonorità (accordo di La minore) ma la sua funzione armonica cambia — tonica in C, sottodominante in G","Am è suonato diversamente in ciascuna tonalità","Am è un errore in una delle due tonalità"], a:1, fb:"L'accordo Am (La–Do–Mi) rimane identico. Cambia solo la sua interpretazione funzionale: in C è un'alternativa alla tonica (VI). In G è un accordo preparatorio verso D7 (SD). Stesso suono, due ruoli." },
{ q:"Il 6/4 di cadenza è:", opts:["Un accordo di sesta aggiunta","Il I grado in secondo rivolto — la quinta è al basso","Il V grado in primo rivolto","Un accordo di sesta napoletana"], a:1, fb:"I6/4 = primo grado in 2° rivolto (la quinta al basso). In C: C/G (Do–Mi–Sol con Sol al basso). Gli intervalli sopra il basso sono una sesta (Mi–Sol) e una quarta (Sol–Do) — da cui il nome 6/4." },
{ q:"Perché il 6/4 di cadenza è collocato subito prima della dominante?", opts:["Per convenzione arbitraria","Perché le sue note (quarta e sesta sul basso) agiscono come appoggiature della quinta e della terza di V","Perché è più grave","Perché sostituisce la sottodominante"], a:1, fb:"Il 6/4 di cadenza contiene Do (quarta) e Mi (sesta) sopra Sol. Queste due note scendono congiuntamente verso Si (terza di G7) e Re (quinta di G7). È una doppia appoggiatura della dominante." },
{ q:"In C maggiore, il 6/4 di cadenza si scrive:", opts:["C/E","G/B","C/G","F/C"], a:2, fb:"C/G = Do–Mi–Sol con Sol al basso. È il I in 2° rivolto. Sol è la quinta di C — da cui il nome I6/4 (sesta Do–Mi e quarta Sol–Do sopra il basso Sol)." },
{ q:"La risoluzione del 6/4 di cadenza verso V7 avviene tramite:", opts:["Un salto di quinta","La quarta che scende verso la terza di V, e la sesta che scende verso la quinta di V","Un movimento ascendente","Un salto di terza"], a:1, fb:"Do (quarta) scende verso Si (terza di G7). Mi (sesta) scende verso Re (quinta di G7). Sol (basso) rimane — è la fondamentale di G. Due discese congiunte: Do→Si e Mi→Re. Il basso Sol rimane immobile." },
{ q:"La sequenza I6/4 → V7 → I è:", opts:["Una cadenza imperfetta","Una cadenza perfetta rinforzata — il 6/4 di cadenza prepara il V7 con più tensione","Una cadenza d'inganno","Una semicadenza"], a:1, fb:"I6/4 → V7 → I è una cadenza perfetta con preparazione. Il 6/4 rinforza la tensione prima di V7 — doppia appoggiatura che amplifica l'attesa della risoluzione. Molto usato nei concerti classici." },
{ q:"Il V7sus4 è:", opts:["V7 con una settima sospesa","V7 in cui la terza è temporaneamente sostituita da una quarta (spesso la tonica)","V7 in primo rivolto","V7 con una 9a aggiunta"], a:1, fb:"V7sus4 = accordo di dominante 7 con sospensione di quarta: la terza (Si in G7) è sostituita dalla quarta (Do). In G7sus4: Sol–Do–Re–Fa. La quarta (Do) si risolve poi sulla terza (Si): V7sus4 → V7." },
{ q:"In C maggiore, G7sus4 contiene le note:", opts:["Sol–Si–Re–Fa","Sol–Do–Re–Fa","Sol–Si–Mi–Fa","Sol–Do–Mi–Fa"], a:1, fb:"G7sus4 = Sol–Do–Re–Fa. La terza Si è sostituita dalla quarta Do. La quarta Do scende verso Si per dare G7 = Sol–Si–Re–Fa. V7sus4 → V7 → I." },
{ q:"La risoluzione del V7sus4 verso V7 avviene tramite:", opts:["Un salto di quinta","La quarta (Do in G7sus4) che scende di un semitono verso la terza (Si in G7)","Un movimento ascendente","Il basso che sale"], a:1, fb:"In G7sus4 → G7: Do (quarta sospesa) scende di un semitono verso Si (terza). La sospensione si scioglie — la tensione si risolve verso la vera dominante G7 prima della risoluzione finale su C." },
{ q:"Il V7sus4 crea una tensione più morbida di V7 perché:", opts:["È più grave","La quarta sostituisce la terza — nessuna sensibile (Si) nell'accordo, meno tensione cromatica","È più rapido","Ha meno note"], a:1, fb:"G7sus4 non contiene Si (la sensibile di C). L'accordo è meno teso di un G7 completo. La sospensione crea un'attesa elegante — quando Si arriva finalmente (V7sus4 → V7), la risoluzione su C è molto soddisfacente." },
{ q:"La sequenza SD → I6/4 → V7 → I è:", opts:["Una cadenza imperfetta","Una cadenza perfetta con doppia preparazione — SD prepara 6/4, 6/4 prepara V7","Una semicadenza","Una cadenza d'inganno"], a:1, fb:"SD prepara 6/4 che prepara V7 che risolve su I. Tre fasi di preparazione crescente — ogni accordo amplifica la tensione prima della risoluzione finale. Formula classica per le grandi cadenze." },
{ q:"Il 6/4 di cadenza è usato per:", opts:["Iniziare una frase","Confermare l'arrivo in una nuova tonalità prima della cadenza perfetta","Creare una pedale di dominante","Sostituire la sottodominante"], a:1, fb:"Il 6/4 di cadenza (I6/4 della nuova tonalità) è spesso collocato subito prima della cadenza perfetta — annuncia fortemente la risoluzione imminente. È una 'bandiera armonica' della nuova tonalità." },
{ q:"In un concerto classico, il 6/4 di cadenza è spesso seguito da:", opts:["La melodia principale","Un assolo cadenza — la doppia appoggiatura risolve verso la dominante su cui l'interprete improvvisa","La ricapitolazione diretta","Un accordo napoletano"], a:1, fb:"La cadenza del concerto usa il 6/4 per segnare l'inizio della cadenza del solista. Il 6/4 (Sol al basso) è tenuto mentre il solista improvvisa, poi l'orchestra risolve V7–I alla fine." },
{ q:"Il V7sus4 è particolarmente usato in:", opts:["Solo nella musica barocca","Il jazz, il post-romanticismo e la musica moderna — per la sua preparazione elegante","La musica medievale","Solo nelle fughe"], a:1, fb:"V7sus4 è molto apprezzato nel jazz (Herbie Hancock, Bill Evans), nel post-romanticismo (Wagner, Debussy) e nel pop/rock moderno. Offre una preparazione più colorata e meno convenzionale del V diretto." },
{ q:"Il 6/4 di cadenza è talvolta chiamato 'quarta e sesta' perché:", opts:["Ha quattro note e sei accordi","Gli intervalli sopra il basso sono una quarta e una sesta (dal basso alle note dell'accordo)","Dura quattro misure","È in 6/4 di tempo"], a:1, fb:"Sopra il basso Sol: Do è una quarta (Sol→Do = 4 gradi) e Mi è una sesta (Sol→Mi = 6 gradi). Questi due intervalli caratterizzano il I6/4 = 'accordo di quarta e sesta' o '6/4 di cadenza'." },
{ q:"Qual è la differenza tra I6/4 e I6?", opts:["Nessuna differenza","I6/4 = 2° rivolto (quinta al basso), I6 = 1° rivolto (terza al basso)","I6 = 2° rivolto","I6/4 ha una nota in più"], a:1, fb:"I6 = primo rivolto: la terza è al basso (C/E in C). I6/4 = secondo rivolto: la quinta è al basso (C/G in C). La notazione cifrata 6/4 e 6 proviene dal basso cifrato barocco." },
{ q:"La sequenza V7sus4 → V7 → I evoca implicitamente:", opts:["Due toniche successive","La presenza del I e del VII grado nel movimento delle voci — Do (tonica) in sus4 scende verso Si (sensibile) che sale verso Do","Un prestito alla dominante","Un accordo napoletano"], a:1, fb:"Do (quarta sospesa in G7sus4) scende verso Si (terza di G7 = sensibile di C). Poi Si sale verso Do (risoluzione finale). Il Do → Si → Do è un movimento sospensione-sensibile-risoluzione implicito nella voce." },
{ q:"Per quale ragione il 6/4 di cadenza deve avere il basso raddoppiato?", opts:["Per estetica","Perché il basso (quinta dell'accordo) è il suono più stabile del I6/4 — raddoppiarlo rinforza l'accordo","Perché la terza è instabile","Solo per convenzione"], a:1, fb:"In I6/4, il basso è la quinta dell'accordo. La regola di raddoppio del 6/4 di cadenza: raddoppiare il basso (= la quinta). La quinta è la nota più neutra — raddoppiarla stabilizza l'accordo instabile." },
];

const questionsPt: Question[] = [{ q:"Uma modulação é:", opts:["Um empréstimo de acorde estranho","Uma mudança duradoura de tonalidade principal — o centro tonal se desloca","Uma tonicização prolongada","Uma mudança de tempo"], a:1, fb:"A modulação instala duravelmente uma nova tonalidade — ela é confirmada por uma cadência perfeita no novo centro. Distingue-se do empréstimo (momentâneo) e da tonicização (breve)." },
{ q:"Qual condição torna uma modulação 'real' (duradoura)?", opts:["Utilizar um acorde diminuto","A confirmação por uma cadência perfeita na nova tonalidade, seguida de uma permanência","O uso de acordes invertidos","A presença de uma sensível artificial"], a:1, fb:"Uma modulação não é uma simples cor passageira — ela instala um novo centro tonal. Para isso, uma cadência perfeita (V–I) no novo tom confirma a chegada. Sem essa permanência, trata-se de uma tonicização." },
{ q:"O que distingue fundamentalmente uma modulação de um empréstimo?", opts:["A duração — modulação = duradoura, empréstimo = momentâneo","A altura das notas","O número de vozes","A armadura somente"], a:0, fb:"Um empréstimo é uma cor passageira — retorna-se imediatamente à tonalidade principal. A modulação desloca duravelmente o centro tonal — permanece-se na nova tonalidade por vários compassos." },
{ q:"A modulação por acorde pivô é a mais frequente porque:", opts:["É a mais rápida","É a mais fluida — o acorde pivô pertence às duas tonalidades, assegurando uma transição sem ruptura","Evita a dominante","Não necessita de cadência"], a:1, fb:"O acorde pivô pertence simultaneamente à tonalidade de partida e à de chegada. Reinterpreta-se (mesmo acorde, nova função) — a transição é, portanto, imperceptível, sem ruptura." },
{ q:"Para confirmar a chegada em uma nova tonalidade, utiliza-se:", opts:["Um acorde invertido","Uma cadência perfeita (V–I) no novo tom","Um acorde de sexta napolitana","Um pedal de tônica"], a:1, fb:"A cadência perfeita na nova tonalidade — V (estado fundamental) → I (estado fundamental) — é o sinal mais forte de que o centro tonal mudou. Sem ela, a modulação permanece ambígua." },
{ q:"Os tons vizinhos são privilegiados para as modulações porque:", opts:["Têm menos notas","Compartilham muitos acordes — os pivôs abundam, a transição é suave","São mais graves","Utilizam menos alterações"], a:1, fb:"Tons vizinhos = 6-7 notas comuns. Quanto mais as duas tonalidades compartilham notas e acordes, mais pivôs são possíveis e mais fluida é a modulação. Os tons distantes exigem transições mais abruptas." },
{ q:"Uma modulação direta (sem pivô) cria:", opts:["Uma transição muito suave","Uma ruptura brusca — efeito teatral ou dramático","Uma cadência imperfeita","Um retardo harmônico"], a:1, fb:"A modulação direta (sem acorde de transição) salta bruscamente de uma tonalidade para outra. Esse efeito pode ser intencional — para marcar uma mudança dramática — mas permanece uma exceção estilística." },
{ q:"A tônica da tonalidade de chegada é geralmente evitada como pivô porque:", opts:["É sempre diminuta","É muito marcada — ouvir a tônica do novo tom antes da cadência enfraquece a surpresa da chegada","Não pertence à escala de partida","Cria oitavas paralelas"], a:1, fb:"Se a tônica de G (G maior) for ouvida muito cedo como acorde diatônico de C (V de C), o ouvido antecipa a chegada. O acorde pivô ideal é neutro — não prefigura demasiadamente o destino." },
{ q:"Por quanto tempo é preciso permanecer na nova tonalidade para validar uma modulação?", opts:["Um único acorde é suficiente","Ao menos uma cadência perfeita — de preferência vários compassos","Exatamente 4 compassos","Uma oitava de duração"], a:1, fb:"Uma modulação só é validada se houver permanência na nova tonalidade. Um único acorde da nova tonalidade é uma tonicização. É preciso no mínimo uma cadência perfeita, idealmente vários compassos." },
{ q:"Na progressão C–F–G7–C–Am–D7–G, a modulação de C para G é confirmada por:", opts:["Am","D7","G — o acorde final","A presença de F# em D7"], a:1, fb:"D7 é a dominante de G. D7–G é a cadência perfeita em G maior. É D7 que confirma que estamos em G — ele contém F# (sensível de G) que sobe para Sol." },
{ q:"A modulação para a dominante (ex.: C→G) é a mais frequente na música clássica porque:", opts:["É a mais dramática","G é o tom mais próximo de C — compartilham 6 notas e vários acordes comuns","C e G têm a mesma armadura","Evita o trítono"], a:1, fb:"C e G diferem em apenas uma nota (F vs F#). É a modulação mais natural — muito frequente em Bach, Haydn, Mozart. A modulação para a dominante é frequentemente usada para a seção B ou o desenvolvimento." },
{ q:"A modulação para o relativo menor (ex.: C→Am) é característica de:", opts:["A cadência plagal","Numerosas formas musicais — o trio, a seção contrastante","O pedal de dominante","O ciclo das quintas"], a:1, fb:"C maior e Am compartilham exatamente as mesmas notas. A modulação para o relativo menor cria um deslizamento para uma cor mais sombria sem alterar as notas da escala — muito natural e muito frequente." },
{ q:"Para modular de C maior para E♭ maior (tom distante), pode-se utilizar:", opts:["Um acorde pivô direto (compartilham poucos acordes)","Uma série de empréstimos graduais ou uma modulação direta dramática","Um baixo de chacona","O ciclo das quintas completo"], a:1, fb:"C e Eb são distantes (3 bemóis de diferença). Um pivô direto é difícil — pode-se passar por tons intermediários (empréstimos progressivos, cromatismo) ou modular diretamente para um efeito dramático." },
{ q:"O que é um 'esquema de modulação típico'?", opts:["Um acorde pivô fixo","I–IV–V–I (na partida), pivô, V–I (na chegada) — ou seja, T→SD na partida, pivô, D→T na chegada","Duas cadências perfeitas consecutivas","Uma mudança brusca de armadura"], a:1, fb:"Esquema típico: T–SD (na tonalidade de partida) → acorde pivô (reinterpretado) → D–T (cadência perfeita na nova tonalidade). O pivô é frequentemente uma subdominante ou um acorde neutro." },
{ q:"Por que a subdominante é frequentemente escolhida como acorde pivô?", opts:["Por ser a mais grave","Por preparar naturalmente a dominante da nova tonalidade — ela está funcionalmente em 'espera'","Por ter sempre uma quinta justa","Por ser sempre maior"], a:1, fb:"A subdominante prepara a dominante — essa é sua função. Usada como pivô, reinterpreta-se como SD da nova tonalidade e naturalmente convoca a dominante que confirma a chegada." },
{ q:"A modulação pode ser preparada por:", opts:["Qualquer acorde sem preparação","Uma tonicização progressiva em direção à nova tonalidade — V/V pode preparar a modulação para V","Um acorde napolitano somente","Um pedal de baixo obrigatório"], a:1, fb:"Uma tonicização para V (ex.: D7 em C que prepara G) pode tornar-se uma modulação se permanecermos em G. O V/V prepara tão naturalmente a nova tônica (G) que a transição parece evidente." },
{ q:"Em uma modulação por acorde pivô, quantas funções tem o acorde pivô?", opts:["Uma única","Duas — uma em cada tonalidade (partida e chegada)","Três","Nenhuma — ele é neutro"], a:1, fb:"O acorde pivô tem duas funções simultâneas: uma na tonalidade de partida, outra na de chegada. É essa dupla pertença que permite a transição sem ruptura." },
{ q:"A modulação é frequentemente usada nas formas musicais para:", opts:["Acelerar o tempo","Criar contraste e dar movimento ao discurso musical — seções A e B, desenvolvimento","Evitar repetições de melodia","Simplificar a harmonia"], a:1, fb:"A modulação é um poderoso instrumento formal — ela cria contraste harmônico entre as seções de uma peça. A forma sonata explora sistematicamente a modulação para a dominante no desenvolvimento." },
{ q:"Um acorde pivô é:", opts:["Um acorde tocado muito forte","Um acorde pertencente simultaneamente a duas tonalidades diferentes — ele assegura a transição","Um acorde de dominante secundária","Um acorde em segundo estado de inversão"], a:1, fb:"O acorde pivô é um acorde que pertence às duas tonalidades — partida e chegada. Toca-se uma vez com sua função de partida, depois reinterpreta-se na nova tonalidade. É a dobradiça da modulação." },
{ q:"Qual propriedade faz de um acorde um bom pivô?", opts:["Ser maior","Pertencer às duas tonalidades e ter uma função natural em cada uma — idealmente não-cadencial","Estar no estado fundamental","Não ter nenhuma alteração"], a:1, fb:"Um bom pivô pertence às duas tonalidades e tem uma função musicalmente lógica em cada uma. É idealmente não-cadencial (nem a dominante nem a tônica principal) para não marcar demasiadamente a direção." },
{ q:"Ao modular de C para G, Am é um excelente pivô porque:", opts:["Am é maior nas duas tonalidades","Am é VI em C (tônica secundária) e II em G (subdominante) — duas funções naturais","Am é a dominante dos dois","Am contém todas as notas das duas escalas"], a:1, fb:"Am = VI em C (tônica, papel estável) e II em G (subdominante, prepara D7). A reinterpretação é natural — Am como VI em C desliza para Am como II em G, que convoca D7–G." },
{ q:"Ao modular de C para G, Em é um pivô:", opts:["Impossível — Em não está em G","Possível — Em é III em C e VI em G, duas funções tônicas","Muito comum e cadencial","Impossível pois Em é diminuto em G"], a:1, fb:"Em é III em C (tônica) e VI em G (tônica). É um pivô válido — Em tem a mesma sonoridade nas duas tonalidades (tônica secundária). É menos comum que Am, mas funciona." },
{ q:"Por que se evita G como pivô ao modular de C para G?", opts:["G não está em C","G é a tônica de chegada — usá-lo como pivô cedo demais revela prematuramente o destino","G é sempre menor","G cria oitavas paralelas"], a:1, fb:"G é a tônica de G maior. Se for ouvido muito cedo como V de C (sua função em C), o ouvido antecipa a chegada e perde a surpresa. Prefere-se um pivô mais neutro — Am ou Em." },
{ q:"Os acordes comuns entre C maior e G maior são:", opts:["C, Dm, Em, F, G, Am","C, Em, G, Am (e Bdim em C = Em em G)","G, D, A, E, B","F, Bb, Eb"], a:1, fb:"C maior: C Dm Em F G7 Am Bdim. G maior: G Am Bm C D7 Em F#dim. Acordes comuns: C (I em C / IV em G), Em (III em C / VI em G), Am (VI em C / II em G), G (V em C / I em G)." },
{ q:"Ao modular de G para D, Bm é um bom pivô porque:", opts:["Bm é maior nos dois","Bm é III em G (tônica) e VI em D (tônica secundária) — duas funções estáveis","Bm é a dominante de G","Bm não existe em D"], a:1, fb:"Bm é III de G e VI de D — tônica nas duas tonalidades. É o pivô mais natural para a modulação G→D, simétrico ao Am para C→G." },
{ q:"A progressão C–Am–D7–G ilustra:", opts:["Uma tonicização de Am","Uma modulação de C para G com Am como pivô","Uma cadência interrompida","Um baixo de chacona"], a:1, fb:"Am é pivô: VI em C (tônica, a progressão começa em C) → II em G (subdominante). D7 é a dominante de G. A cadência D7–G confirma G maior como novo centro tonal." },
{ q:"Ao modular de F para C, Dm é um pivô porque:", opts:["Dm é maior nos dois","Dm é VI em F e II em C — funções tônica e subdominante","Dm é a dominante de F","Dm não existe em C"], a:1, fb:"Dm é VI de F (tônica secundária) e II de C (subdominante). Ao modular F→C, Dm se reinterpreta e prepara G7 (V de C). A cadência G7–C confirma C." },
{ q:"Para encontrar um acorde pivô, busca-se:", opts:["Um acorde maior qualquer","Os acordes comuns às duas tonalidades — lista-se os acordes de cada escala e encontram-se as interseções","Um acorde diminuto","Um acorde invertido"], a:1, fb:"Método: (1) listar todos os acordes da escala de partida, (2) listar todos os acordes da escala de chegada, (3) encontrar os acordes comuns, (4) escolher aquele com as funções mais musicais." },
{ q:"O pivô ideal é geralmente:", opts:["A tônica da escala de partida","Uma subdominante ou um acorde de função tônica secundária — nem muito marcado nem muito instável","A dominante da escala de chegada","Um acorde diminuto"], a:1, fb:"Nem a tônica principal (muito marcada) nem a dominante (muito cadencial) — o pivô ideal é um acorde intermediário: VI ou II de partida (= II ou VI de chegada). Am para C→G é o exemplo clássico." },
{ q:"Em C maior, F é um acorde comum a:", opts:["C maior e G maior","C maior e F maior (I de F) e Bb maior (V de Bb)","C maior e D menor","C maior e E menor"], a:1, fb:"F (Fá maior) é IV de C, I de F e V de Bb. Ao modular de C para F, F seria a tônica de chegada — a evitar como pivô. Para Bb, F poderia ser pivô (V de Bb = SD de C — papel semelhante)." },
{ q:"A notação 'pivô' em uma análise harmônica é frequentemente escrita:", opts:["Em vermelho","Com um colchete duplo — o mesmo compasso anotado nas duas tonalidades (ex.: [VI em C = II em G])","Em 3/4","Com um acorde diminuto"], a:1, fb:"O acorde pivô é anotado duplamente: VI em C / II em G (ou similar). Essa dupla anotação mostra explicitamente a reinterpretação — mesmo acorde, duas leituras funcionais simultâneas." },
{ q:"Ao modular de Am para C maior, qual acorde pode servir de pivô?", opts:["G7","Em — III de C e VI de Am (os dois relativos compartilham todos os seus acordes)","Dm","Bdim"], a:1, fb:"Am e C são relativos — compartilham exatamente as mesmas 7 notas e os mesmos acordes. Qualquer acorde pode ser pivô. Em é frequentemente usado: III de C e VI de Am — duas funções tônicas." },
{ q:"Ao modular de C para Eb (mediante inferior), os acordes comuns são:", opts:["Numerosos — 6 acordes comuns","Raros — C e Eb compartilham apenas Cm (I de Cm e VI de Eb) e Gm","Nenhum — modulação direta obrigatória","F e Bb somente"], a:1, fb:"C maior e Eb maior não compartilham muitos acordes diatônicos. Cm pode servir de pivô (minorização de C → I de Cm → VI de Eb). É uma modulação mais complexa." },
{ q:"A progressão G–Em–Am–D7–G (em G maior) mostra:", opts:["Uma modulação para Am","Uma cadência perfeita em G com Am como acorde de passagem","Um retorno a G sem modulação — Am é II de G (subdominante)","Uma tonicização de D"], a:1, fb:"Não há modulação aqui — Am é simplesmente II de G (subdominante), Em é VI de G (tônica). A progressão é T–T–SD–D–T em G maior. Am não mudou de tonalidade." },
{ q:"Ao modular de D para A, F#m é um pivô porque:", opts:["F#m é maior em D","F#m é III em D (tônica) e VI em A (tônica) — duas funções estáveis","F#m é a dominante de D","F#m só existe em A"], a:1, fb:"F#m é o III grau de D maior e o VI grau de A maior — tônica nas duas tonalidades. É o pivô natural para D→A, assim como Bm o é para G→D e Am para C→G." },
{ q:"Qual acorde comum a C e F é um bom pivô para modular C→F?", opts:["C (tônica de partida — muito marcado)","Am — VI em C e III em F (duas tônicas)","G7 (dominante de C — muito cadencial)","Bdim"], a:1, fb:"Am é VI de C (tônica) e III de F (tônica também). É um pivô neutro e natural. Após Am em C, pode-se reinterpretar Am como III de F e partir para C7–F para confirmar F maior." },
{ q:"Para modular de C para Bb, pode-se usar Dm como pivô porque:", opts:["Dm é I de Bb","Dm é II em C (subdominante) e III em Bb (tônica) — duas funções","Dm é a dominante de Bb","Dm não está em Bb"], a:1, fb:"Dm é II de C (SD) e III de Bb (tônica). Reinterpretando Dm como III de Bb, pode-se encadear F7 (V de Bb) e depois Bb. A modulação C→Bb é uma modulação para a subdominante." },
{ q:"A modulação de C para Am (relativo menor):", opts:["Necessita de muitos acordes pivôs","É a mais fácil — Am e C compartilham todos os seus acordes, qualquer acorde pode servir de pivô","Necessita de uma cadência direta","É impossível sem modulação cromática"], a:1, fb:"C e Am são relativos — mesmas notas, mesma armadura. Qualquer acorde comum pode servir de pivô. Na prática, Em (III/C = VI/Am) ou G (V/C = VII/Am) são comuns para essa transição." },
{ q:"A progressão C–F–G7–C–Am–E7–Am mostra:", opts:["Uma modulação para Am com Am–E7–Am como cadência perfeita em Am (E7 = V de Am harmônico)","Um empréstimo de E7","Uma tonicização sem modulação","Uma cadência plagal em C"], a:0, fb:"E7 é V de Am harmônico (Mi–Sol#–Si–Ré). E7–Am é uma cadência perfeita em Lá menor. Se a progressão permanecer em Am após, trata-se de uma modulação. A progressão C–Am é o pivô (VI de C = I de Am), depois E7–Am confirma Am." },
{ q:"O pivô 'Am = VI em C / II em G' significa que:", opts:["Am muda de sonoridade conforme a tonalidade","Am mantém a mesma sonoridade (acorde de Lá menor) mas sua função harmônica muda — tônica em C, subdominante em G","Am é tocado de forma diferente em cada tonalidade","Am é um erro em uma das duas tonalidades"], a:1, fb:"O acorde Am (Lá–Dó–Mi) permanece idêntico. Apenas sua interpretação funcional muda: em C, é uma alternativa à tônica (VI). Em G, é um acorde preparatório para D7 (SD). Mesmo som, dois papéis." },
{ q:"O 6/4 de cadência é:", opts:["Um acorde de sexta acrescentada","O I grau em segundo estado de inversão — a quinta está no baixo","O V grau em primeiro estado de inversão","Um acorde de sexta napolitana"], a:1, fb:"I6/4 = primeiro grau em 2ª inversão (a quinta no baixo). Em C: C/G (Dó–Mi–Sol com Sol no baixo). Os intervalos acima do baixo são uma sexta (Mi–Sol) e uma quarta (Sol–Dó) — daí o nome 6/4." },
{ q:"Por que o 6/4 de cadência é colocado logo antes da dominante?", opts:["Por convenção arbitrária","Porque suas notas (quarta e sexta sobre o baixo) agem como apojaturas da quinta e da terça de V","Por ser mais grave","Por substituir a subdominante"], a:1, fb:"O 6/4 de cadência contém Dó (quarta) e Mi (sexta) acima de Sol. Essas duas notas descem conjuntamente para Si (terça de G7) e Ré (quinta de G7). É uma dupla apojatura da dominante." },
{ q:"Em C maior, o 6/4 de cadência escreve-se:", opts:["C/E","G/B","C/G","F/C"], a:2, fb:"C/G = Dó–Mi–Sol com Sol no baixo. É o I em 2ª inversão. Sol é a quinta de C — daí o nome I6/4 (sexta Dó–Mi e quarta Sol–Dó acima do baixo Sol)." },
{ q:"A resolução do 6/4 de cadência para V7 se faz por:", opts:["Um salto de quinta","A quarta que desce para a terça de V, e a sexta que desce para a quinta de V","Um movimento ascendente","Um salto de terça"], a:1, fb:"Dó (quarta) desce para Si (terça de G7). Mi (sexta) desce para Ré (quinta de G7). Sol (baixo) permanece — é a fundamental de G. Duas descidas conjuntas: Dó→Si e Mi→Ré. O baixo Sol fica imóvel." },
{ q:"A sequência I6/4 → V7 → I é:", opts:["Uma cadência imperfeita","Uma cadência perfeita reforçada — o 6/4 de cadência prepara o V7 com mais tensão","Uma cadência interrompida","Uma meia-cadência"], a:1, fb:"I6/4 → V7 → I é uma cadência perfeita com preparação. O 6/4 reforça a tensão antes de V7 — dupla apojatura que amplifica a expectativa de resolução. Muito usado nos concertos clássicos." },
{ q:"O V7sus4 é:", opts:["V7 com uma sétima suspensa","V7 em que a terça é temporariamente substituída por uma quarta (frequentemente a tônica)","V7 em primeiro estado de inversão","V7 com uma 9ª acrescentada"], a:1, fb:"V7sus4 = acorde de dominante 7 com suspensão de quarta: a terça (Si em G7) é substituída pela quarta (Dó). Em G7sus4: Sol–Dó–Ré–Fá. A quarta (Dó) resolve depois na terça (Si): V7sus4 → V7." },
{ q:"Em C maior, G7sus4 contém as notas:", opts:["Sol–Si–Ré–Fá","Sol–Dó–Ré–Fá","Sol–Si–Mi–Fá","Sol–Dó–Mi–Fá"], a:1, fb:"G7sus4 = Sol–Dó–Ré–Fá. A terça Si é substituída pela quarta Dó. A quarta Dó desce para Si, dando G7 = Sol–Si–Ré–Fá. V7sus4 → V7 → I." },
{ q:"A resolução do V7sus4 para V7 se faz por:", opts:["Um salto de quinta","A quarta (Dó em G7sus4) que desce meio tom para a terça (Si em G7)","Um movimento ascendente","O baixo que sobe"], a:1, fb:"Em G7sus4 → G7: Dó (quarta suspensa) desce meio tom para Si (terça). A suspensão se levanta — a tensão resolve para a verdadeira dominante G7 antes da resolução final em C." },
{ q:"O V7sus4 cria uma tensão mais suave que V7 porque:", opts:["É mais grave","A quarta substitui a terça — não há sensível (Si) no acorde, menos tensão cromática","É mais rápido","Tem menos notas"], a:1, fb:"G7sus4 não contém Si (a sensível de C). O acorde é menos tenso que um G7 completo. A suspensão cria uma expectativa elegante — quando Si finalmente chega (V7sus4 → V7), a resolução em C é muito satisfatória." },
{ q:"A sequência SD → I6/4 → V7 → I é:", opts:["Uma cadência imperfeita","Uma cadência perfeita com dupla preparação — SD prepara 6/4, 6/4 prepara V7","Uma meia-cadência","Uma cadência interrompida"], a:1, fb:"SD prepara 6/4, que prepara V7, que resolve em I. Três etapas de preparação crescente — cada acorde amplifica a tensão antes da resolução final. Fórmula clássica para as grandes cadências." },
{ q:"O 6/4 de cadência é utilizado para:", opts:["Iniciar uma frase","Confirmar a chegada em uma nova tonalidade antes da cadência perfeita","Criar um pedal de dominante","Substituir a subdominante"], a:1, fb:"O 6/4 de cadência (I6/4 da nova tonalidade) é frequentemente colocado logo antes da cadência perfeita — ele anuncia fortemente a resolução iminente. É uma 'bandeira harmônica' da nova tonalidade." },
{ q:"Em um concerto clássico, o 6/4 de cadência é frequentemente seguido de:", opts:["A melodia principal","Uma cadenza solo — a dupla apojatura resolve para a dominante sobre a qual o intérprete improvisa","A recapitulação direta","Um acorde napolitano"], a:1, fb:"A cadência de concerto usa o 6/4 para marcar o início da cadenza solista. O 6/4 (Sol no baixo) é mantido enquanto o solista improvisa; depois, a orquestra resolve V7–I ao final." },
{ q:"O V7sus4 é particularmente utilizado em:", opts:["A música barroca somente","O jazz, o pós-romantismo e a música moderna — por sua preparação elegante","A música medieval","As fugas somente"], a:1, fb:"V7sus4 é muito apreciado no jazz (Herbie Hancock, Bill Evans), no pós-romantismo (Wagner, Debussy) e na pop/rock moderna. Oferece uma preparação mais colorida e menos convencional que o V direto." },
{ q:"O 6/4 de cadência é às vezes chamado de 'quarta e sexta' porque:", opts:["Tem quatro notas e seis acordes","Os intervalos acima do baixo são uma quarta e uma sexta (do baixo até as notas do acorde)","Dura quatro compassos","Está em compasso 6/4"], a:1, fb:"Acima do baixo Sol: Dó é uma quarta (Sol→Dó = 4 graus) e Mi é uma sexta (Sol→Mi = 6 graus). Esses dois intervalos caracterizam o I6/4 = 'acorde de quarta e sexta' ou '6/4 de cadência'." },
{ q:"Qual é a diferença entre I6/4 e I6?", opts:["Nenhuma diferença","I6/4 = 2ª inversão (quinta no baixo), I6 = 1ª inversão (terça no baixo)","I6 = 2ª inversão","I6/4 tem uma nota a mais"], a:1, fb:"I6 = primeira inversão: a terça está no baixo (C/E em C). I6/4 = segunda inversão: a quinta está no baixo (C/G em C). A notação cifrada 6/4 e 6 provém do baixo cifrado barroco." },
{ q:"A sequência V7sus4 → V7 → I evoca implicitamente:", opts:["Duas tônicas sucessivas","A presença do I e do VII graus no movimento de vozes — Dó (tônica) no sus4 desce para Si (sensível) que sobe para Dó","Um empréstimo à dominante","Um acorde napolitano"], a:1, fb:"Dó (quarta suspensa em G7sus4) desce para Si (terça de G7 = sensível de C). Depois Si sobe para Dó (resolução final). O Dó → Si → Dó é um movimento de suspensão-sensível-resolução implícito na voz." },
{ q:"Por que o 6/4 de cadência deve ter o baixo dobrado?", opts:["Por estética","Porque o baixo (quinta do acorde) é o som mais estável do I6/4 — dobrá-lo reforça o acorde","Porque a terça é instável","Por convenção somente"], a:1, fb:"No I6/4, o baixo é a quinta do acorde. A regra de dobramento do 6/4 de cadência: dobrar o baixo (= a quinta). A quinta é a nota mais neutra — dobrá-la estabiliza o acorde instável." },
{ q:"Após I6/4 → V7, pode-se inserir V7sus4 entre os dois?", opts:["Não — V7sus4 deve sempre preceder V7 diretamente","Sim: I6/4 → V7sus4 → V7 → I é possível e cria uma tensão ainda mais gradual","Não — o 6/4 e o sus4 se excluem","Somente em menor"], a:1, fb:"A sequência I6/4 → V7sus4 → V7 → I é perfeitamente válida e elaborada. Cada etapa adiciona uma camada de tensão: 6/4 prepara sus4, sus4 libera a quarta para a terça, V7 resolve em I." },
];

